            bindServer(ps, 1);
            try (ResultSet rs = ps.executeQuery()) { while (rs.next()) list.add(mapSession(rs)); }
        } catch (SQLException e) { FppLogger.error("DB getActiveSessions: " + e.getMessage()); }
        return list;
    }

