    public int getTotalSessionCount() {
        if (!isAlive()) return 0;
        try (Statement st = connection.createStatement();
             ResultSet rs = st.executeQuery(
                "SELECT COUNT(*) FROM fpp_bot_sessions" + serverWhere())) {
            if (rs.next()) return rs.getInt(1);
        } catch (SQLException e) { FppLogger.error("DB getTotalSessionCount: " + e.getMessage()); }
        return 0;
    }

    public int getActiveSessionCount() {
        if (!isAlive()) return 0;
        try (Statement st = connection.createStatement();
             ResultSet rs = st.executeQuery(
                "SELECT COUNT(*) FROM fpp_bot_sessions WHERE removed_at IS NULL" + serverAnd())) {
            if (rs.next()) return rs.getInt(1);
        } catch (SQLException e) { FppLogger.error("DB getActiveSessionCount: " + e.getMessage()); }
        return 0;
    }

    /** Returns the number of distinct bot names ever recorded. */
    public int getUniqueBotCount() {
        if (!isAlive()) return 0;
        try (Statement st = connection.createStatement();
             ResultSet rs = st.executeQuery(
                "SELECT COUNT(DISTINCT bot_name) FROM fpp_bot_sessions" + serverWhere())) {
            if (rs.next()) return rs.getInt(1);
        } catch (SQLException e) { FppLogger.error("DB getUniqueBotCount: " + e.getMessage()); }
        return 0;
    }

    /** Returns the number of distinct players who have ever spawned a bot. */
    public int getUniqueSpawnerCount() {
        if (!isAlive()) return 0;
        try (Statement st = connection.createStatement();
             ResultSet rs = st.executeQuery(
                "SELECT COUNT(DISTINCT spawned_by) FROM fpp_bot_sessions" + serverWhere())) {
            if (rs.next()) return rs.getInt(1);
        } catch (SQLException e) { FppLogger.error("DB getUniqueSpawnerCount: " + e.getMessage()); }
        return 0;
    }

    /**
     * Returns the top {@code limit} spawners by total bot spawns, as
     * {@code Map<playerName, spawnCount>} in descending order.
     */
    public Map<String, Integer> getTopSpawners(int limit) {
        Map<String, Integer> result = new LinkedHashMap<>();
        if (!isAlive()) return result;
        try (PreparedStatement ps = connection.prepareStatement(
                "SELECT spawned_by, COUNT(*) AS cnt FROM fpp_bot_sessions WHERE " + serverCond() +
                " GROUP BY spawned_by ORDER BY cnt DESC LIMIT ?")) {
            int next = bindServer(ps, 1);
            ps.setInt(next, limit);
            try (ResultSet rs = ps.executeQuery()) {
                while (rs.next()) result.put(rs.getString("spawned_by"), rs.getInt("cnt"));
            }
        } catch (SQLException e) { FppLogger.error("DB getTopSpawners: " + e.getMessage()); }
        return result;
    }

    /**
     * Returns aggregated plugin statistics.
     * All values are scoped to the current server (LOCAL mode) or global (NETWORK mode).
     */
    public DbStats getStats() {
        if (!isAlive()) return new DbStats(0, 0, 0, 0, 0L, isMysql ? "MySQL" : "SQLite");
        int total = 0, active = 0, unique = 0, uniqueSpawners = 0;
        long totalUptimeMs = 0L;
        try (Statement st = connection.createStatement()) {
            try (ResultSet rs = st.executeQuery(
                    "SELECT COUNT(*) FROM fpp_bot_sessions" + serverWhere())) {
                if (rs.next()) total = rs.getInt(1);
            }
            try (ResultSet rs = st.executeQuery(
                    "SELECT COUNT(*) FROM fpp_bot_sessions WHERE removed_at IS NULL" + serverAnd())) {
                if (rs.next()) active = rs.getInt(1);
            }
            try (ResultSet rs = st.executeQuery(
                    "SELECT COUNT(DISTINCT bot_name) FROM fpp_bot_sessions" + serverWhere())) {
                if (rs.next()) unique = rs.getInt(1);
            }
            try (ResultSet rs = st.executeQuery(
                    "SELECT COUNT(DISTINCT spawned_by) FROM fpp_bot_sessions" + serverWhere())) {
                if (rs.next()) uniqueSpawners = rs.getInt(1);
            }
            try (ResultSet rs = st.executeQuery(
                    "SELECT SUM(removed_at - spawned_at) FROM fpp_bot_sessions " +
                    "WHERE removed_at IS NOT NULL" + serverAnd())) {
                if (rs.next()) totalUptimeMs = rs.getLong(1);
            }
        } catch (SQLException e) { FppLogger.error("DB getStats: " + e.getMessage()); }
        return new DbStats(total, active, unique, uniqueSpawners, totalUptimeMs,
                isMysql ? "MySQL" : "SQLite");
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    private void upsertActiveBotSync(String uuid, String name, String display,
                                     String spawnedBy, String spawnedByUuid, String world,
                                     double x, double y, double z,
                                     float yaw, float pitch, String luckpermsGroup) {
        long now = Instant.now().toEpochMilli();
        String serverId = Config.serverId();
        String sql = isMysql
                ? "INSERT INTO fpp_active_bots(bot_uuid,bot_name,bot_display,spawned_by,spawned_by_uuid," +
                  "world_name,pos_x,pos_y,pos_z,pos_yaw,pos_pitch,updated_at,luckperms_group,server_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?) " +
                  "ON DUPLICATE KEY UPDATE bot_name=VALUES(bot_name),bot_display=VALUES(bot_display)," +
                  "spawned_by=VALUES(spawned_by),spawned_by_uuid=VALUES(spawned_by_uuid)," +
                  "world_name=VALUES(world_name),pos_x=VALUES(pos_x),pos_y=VALUES(pos_y)," +
                  "pos_z=VALUES(pos_z),pos_yaw=VALUES(pos_yaw),pos_pitch=VALUES(pos_pitch)," +
                  "updated_at=VALUES(updated_at),luckperms_group=VALUES(luckperms_group)," +
                  "server_id=VALUES(server_id)"
                : "INSERT OR REPLACE INTO fpp_active_bots(bot_uuid,bot_name,bot_display,spawned_by,spawned_by_uuid," +
                  "world_name,pos_x,pos_y,pos_z,pos_yaw,pos_pitch,updated_at,luckperms_group,server_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?)";
        try (PreparedStatement ps = connection.prepareStatement(sql)) {
            ps.setString(1, uuid);  ps.setString(2, name);  ps.setString(3, display);
            ps.setString(4, spawnedBy); ps.setString(5, spawnedByUuid);
            ps.setString(6, world); ps.setDouble(7, x); ps.setDouble(8, y); ps.setDouble(9, z);
            ps.setFloat(10, yaw);   ps.setFloat(11, pitch); ps.setLong(12, now);
            if (luckpermsGroup != null) ps.setString(13, luckpermsGroup);
            else ps.setNull(13, java.sql.Types.VARCHAR);
            ps.setString(14, serverId);
            ps.executeUpdate();
        } catch (SQLException e) { FppLogger.error("DB upsertActiveBot: " + e.getMessage()); }
    }

    private void batchUpdateLocationsSync(Map<String, PendingLocation> snapshot) {
        if (!isAlive() || snapshot.isEmpty()) return;
        long now = Instant.now().toEpochMilli();
        String s1 = "UPDATE fpp_bot_sessions SET last_world=?,last_x=?,last_y=?,last_z=?,last_yaw=?,last_pitch=? WHERE bot_uuid=? AND removed_at IS NULL";
        String s2 = "UPDATE fpp_active_bots SET world_name=?,pos_x=?,pos_y=?,pos_z=?,pos_yaw=?,pos_pitch=?,updated_at=? WHERE bot_uuid=?";
        try (PreparedStatement ps1 = connection.prepareStatement(s1);
             PreparedStatement ps2 = connection.prepareStatement(s2)) {
            for (Map.Entry<String, PendingLocation> e : snapshot.entrySet()) {
                PendingLocation l = e.getValue();
                ps1.setString(1,l.world); ps1.setDouble(2,l.x); ps1.setDouble(3,l.y);
                ps1.setDouble(4,l.z);     ps1.setFloat(5,l.yaw); ps1.setFloat(6,l.pitch);
                ps1.setString(7,e.getKey()); ps1.addBatch();
                ps2.setString(1,l.world); ps2.setDouble(2,l.x); ps2.setDouble(3,l.y);
                ps2.setDouble(4,l.z);     ps2.setFloat(5,l.yaw); ps2.setFloat(6,l.pitch);
                ps2.setLong(7,now); ps2.setString(8,e.getKey()); ps2.addBatch();
            }
            ps1.executeBatch();
            ps2.executeBatch();
            Config.debug("DB flushed " + snapshot.size() + " location(s).");
        } catch (SQLException e) { FppLogger.error("DB batchUpdateLocations: " + e.getMessage()); }
    }

    private void exec(String sql) {
        try (Statement st = connection.createStatement()) { st.execute(sql); }
        catch (SQLException e) { FppLogger.error("DB exec: " + e.getMessage()); }
    }
    private void execSilent(String sql) {
        try (Statement st = connection.createStatement()) { st.execute(sql); }
        catch (SQLException ignored) {}
    }
    private void enqueue(Runnable task) { if (running.get()) writeQueue.offer(task); }

    private BotRecord mapSession(ResultSet rs) throws SQLException {
        long    rm = rs.getLong("removed_at");
        Instant removedAt = rs.wasNull() ? null : Instant.ofEpochMilli(rm);

        double lx = rs.getDouble("last_x"); if (rs.wasNull()) lx = rs.getDouble("spawn_x");
        double ly = rs.getDouble("last_y"); if (rs.wasNull()) ly = rs.getDouble("spawn_y");
        double lz = rs.getDouble("last_z"); if (rs.wasNull()) lz = rs.getDouble("spawn_z");
        String lw = rs.getString("last_world"); if (lw == null) lw = rs.getString("world_name");
        float lyaw, lpitch;
        try { lyaw   = rs.getFloat("last_yaw");   if (rs.wasNull()) lyaw   = rs.getFloat("spawn_yaw");   }
        catch (SQLException ignored) { lyaw = 0f; }
        try { lpitch = rs.getFloat("last_pitch"); if (rs.wasNull()) lpitch = rs.getFloat("spawn_pitch"); }
        catch (SQLException ignored) { lpitch = 0f; }

        // server_id — absent on pre-v6 DBs; fall back to current server
        String sid = null;
        try { sid = rs.getString("server_id"); } catch (SQLException ignored) {}
        if (sid == null || sid.isBlank()) sid = Config.serverId();

        return new BotRecord(
                rs.getLong("id"),
                rs.getString("bot_name"), UUID.fromString(rs.getString("bot_uuid")),
                rs.getString("spawned_by"), UUID.fromString(rs.getString("spawned_by_uuid")),
                rs.getString("world_name"),
                rs.getDouble("spawn_x"), rs.getDouble("spawn_y"), rs.getDouble("spawn_z"),
                rs.getFloat("spawn_yaw"), rs.getFloat("spawn_pitch"),
                lw, lx, ly, lz, lyaw, lpitch,
                Instant.ofEpochMilli(rs.getLong("spawned_at")),
                removedAt, rs.getString("remove_reason"),
                sid
        );
    }

    // ── Sleeping bots API (peak-hours crash-safe persistence) ────────────────

    /**
     * Replaces all sleeping-bot rows for the current server with the supplied list.
     * Called from the main thread whenever the peak-hours sleep queue changes;
     * the actual SQL is enqueued to the write thread (non-blocking).
     *
     * @param bots ordered list of sleeping bots (index = sleep_order); may be empty to clear.
     */
    public void saveSleepingBots(List<SleepingBotRow> bots) {
        final List<SleepingBotRow> snap = new ArrayList<>(bots);
        final String sid = Config.serverId();
        enqueue(() -> {
            if (!isAlive()) return;
            // Atomic replace: delete old rows then insert current queue
            try (PreparedStatement del = connection.prepareStatement(
                    "DELETE FROM fpp_sleeping_bots WHERE server_id=?")) {
                del.setString(1, sid);
                del.executeUpdate();
            } catch (SQLException e) {
                FppLogger.error("DB saveSleepingBots (delete): " + e.getMessage()); return;
            }
            if (snap.isEmpty()) return;
            String sql = "INSERT INTO fpp_sleeping_bots" +
                    "(sleep_order,bot_name,world_name,pos_x,pos_y,pos_z,pos_yaw,pos_pitch,server_id)" +
                    " VALUES(?,?,?,?,?,?,?,?,?)";
            try (PreparedStatement ps = connection.prepareStatement(sql)) {
                for (SleepingBotRow row : snap) {
                    ps.setInt(1,    row.sleepOrder());
                    ps.setString(2, row.botName());
                    ps.setString(3, row.world());
                    ps.setDouble(4, row.x());
                    ps.setDouble(5, row.y());
                    ps.setDouble(6, row.z());
                    ps.setFloat(7,  row.yaw());
                    ps.setFloat(8,  row.pitch());
                    ps.setString(9, sid);
                    ps.addBatch();
                }
                ps.executeBatch();
                Config.debug("DB saved " + snap.size() + " sleeping bot(s) for server='" + sid + "'.");
            } catch (SQLException e) { FppLogger.error("DB saveSleepingBots (insert): " + e.getMessage()); }
        });
    }

    /**
     * Loads sleeping-bot rows for the current server.
     * Intended for startup restore — called synchronously on the main thread.
     *
     * @return ordered list (by sleep_order ASC) of sleeping bot snapshots, never null.
     */
    public List<SleepingBotRow> loadSleepingBots() {
        List<SleepingBotRow> list = new ArrayList<>();
        if (!isAlive()) return list;
        String sql = "SELECT * FROM fpp_sleeping_bots WHERE server_id=? ORDER BY sleep_order ASC";
        try (PreparedStatement ps = connection.prepareStatement(sql)) {
            ps.setString(1, Config.serverId());
            try (ResultSet rs = ps.executeQuery()) {
                while (rs.next()) {
                    list.add(new SleepingBotRow(
                            rs.getInt("sleep_order"),
                            rs.getString("bot_name"),
                            rs.getString("world_name"),
                            rs.getDouble("pos_x"), rs.getDouble("pos_y"), rs.getDouble("pos_z"),
                            rs.getFloat("pos_yaw"), rs.getFloat("pos_pitch")
                    ));
                }
            }
        } catch (SQLException e) { FppLogger.error("DB loadSleepingBots: " + e.getMessage()); }
        return list;
    }

    /**
     * Removes all sleeping-bot rows for the current server.
     * Enqueued to the write thread (non-blocking).
     */
    public void clearSleepingBots() {
        final String sid = Config.serverId();
        enqueue(() -> {
            if (!isAlive()) return;
            try (PreparedStatement ps = connection.prepareStatement(
                    "DELETE FROM fpp_sleeping_bots WHERE server_id=?")) {
                ps.setString(1, sid);
                int rows = ps.executeUpdate();
                Config.debug("DB cleared " + rows + " sleeping bot(s) for server='" + sid + "'.");
            } catch (SQLException e) { FppLogger.error("DB clearSleepingBots: " + e.getMessage()); }
        });
    }

    // ── Merge API (used by DataMigrator) ─────────────────────────────────────

    /**
     * Inserts a session row from an external/old database without overwriting
     * an existing row that has the same {@code bot_uuid} and {@code spawned_at}.
     * Safe to call from any thread (runs synchronously on the calling thread,
     * intended for use from the async DataMigrator task).
     */
    public void mergeSessionRow(
            String botName, String botDisplay, String botUuid,
            String spawnedBy, String spawnedByUuid,
            String worldName,
            double spawnX, double spawnY, double spawnZ,
            float spawnYaw, float spawnPitch,
            String lastWorld, double lastX, double lastY, double lastZ,
            float lastYaw, float lastPitch,
            String entityType,
            long spawnedAtMs, Long removedAtMs, String removeReason,
            String serverId) {

        if (!isAlive()) return;

        if (lastWorld == null) lastWorld = worldName;
        if (entityType == null) entityType = "MANNEQUIN";
        if (serverId == null || serverId.isBlank()) serverId = Config.serverId();

        String sql = isMysql
                ? "INSERT IGNORE INTO fpp_bot_sessions" +
                  "(bot_name,bot_display,bot_uuid,spawned_by,spawned_by_uuid,world_name," +
                  "spawn_x,spawn_y,spawn_z,spawn_yaw,spawn_pitch," +
                  "last_world,last_x,last_y,last_z,last_yaw,last_pitch," +
                  "entity_type,spawned_at,removed_at,remove_reason,server_id) " +
                  "VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)"
                : "INSERT OR IGNORE INTO fpp_bot_sessions" +
                  "(bot_name,bot_display,bot_uuid,spawned_by,spawned_by_uuid,world_name," +
                  "spawn_x,spawn_y,spawn_z,spawn_yaw,spawn_pitch," +
                  "last_world,last_x,last_y,last_z,last_yaw,last_pitch," +
                  "entity_type,spawned_at,removed_at,remove_reason,server_id) " +
                  "VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)";

        try (PreparedStatement ps = connection.prepareStatement(sql)) {
            ps.setString(1,  botName);       ps.setString(2,  botDisplay);
            ps.setString(3,  botUuid);       ps.setString(4,  spawnedBy);
            ps.setString(5,  spawnedByUuid); ps.setString(6,  worldName);
            ps.setDouble(7,  spawnX);        ps.setDouble(8,  spawnY);     ps.setDouble(9,  spawnZ);
            ps.setFloat(10,  spawnYaw);      ps.setFloat(11,  spawnPitch);
            ps.setString(12, lastWorld);
            ps.setDouble(13, lastX);         ps.setDouble(14, lastY);      ps.setDouble(15, lastZ);
            ps.setFloat(16,  lastYaw);       ps.setFloat(17,  lastPitch);
            ps.setString(18, entityType);    ps.setLong(19,   spawnedAtMs);
            if (removedAtMs != null) ps.setLong(20, removedAtMs); else ps.setNull(20, java.sql.Types.BIGINT);
            ps.setString(21, removeReason);
            ps.setString(22, serverId);
            ps.executeUpdate();
        } catch (SQLException e) {
            FppLogger.error("DB mergeSessionRow: " + e.getMessage());
        }
    }

    /**
     * Inserts an active-bot row from an external/old database without overwriting
     * an existing row that has the same {@code bot_uuid}.
     */
    public void mergeActiveBotRow(
            String botUuid, String botName, String botDisplay,
            String spawnedBy, String spawnedByUuid,
            String worldName, double posX, double posY, double posZ,
            float posYaw, float posPitch, long updatedAt,
            String serverId) {

        if (!isAlive()) return;
        if (serverId == null || serverId.isBlank()) serverId = Config.serverId();

        String sql = isMysql
                ? "INSERT IGNORE INTO fpp_active_bots" +
                  "(bot_uuid,bot_name,bot_display,spawned_by,spawned_by_uuid," +
                  "world_name,pos_x,pos_y,pos_z,pos_yaw,pos_pitch,updated_at,server_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)"
                : "INSERT OR IGNORE INTO fpp_active_bots" +
                  "(bot_uuid,bot_name,bot_display,spawned_by,spawned_by_uuid," +
                  "world_name,pos_x,pos_y,pos_z,pos_yaw,pos_pitch,updated_at,server_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)";

        try (PreparedStatement ps = connection.prepareStatement(sql)) {
            ps.setString(1,  botUuid);       ps.setString(2,  botName);
            ps.setString(3,  botDisplay);    ps.setString(4,  spawnedBy);
            ps.setString(5,  spawnedByUuid); ps.setString(6,  worldName);
            ps.setDouble(7,  posX);          ps.setDouble(8,  posY);  ps.setDouble(9,  posZ);
            ps.setFloat(10,  posYaw);        ps.setFloat(11,  posPitch);
            ps.setLong(12,   updatedAt);     ps.setString(13, serverId);
            ps.executeUpdate();
        } catch (SQLException e) {
            FppLogger.error("DB mergeActiveBotRow: " + e.getMessage());
        }
    }

    /**
     * Returns the number of rows in {@code fpp_bot_sessions}.
     * Used by DataMigrator / MigrateCommand to report totals.
     */
    public int countSessions() {
        return getTotalSessionCount();
    }

    /**
     * Returns the number of rows in {@code fpp_active_bots}.
     */
    public int countActiveBotRows() {
        if (!isAlive()) return 0;
        try (Statement st = connection.createStatement();
             ResultSet rs = st.executeQuery("SELECT COUNT(*) FROM fpp_active_bots")) {
            if (rs.next()) return rs.getInt(1);
        } catch (SQLException e) { FppLogger.error("DB countActiveBotRows: " + e.getMessage()); }
        return 0;
    }

    // ── Accessors ─────────────────────────────────────────────────────────────
    public boolean isMysql() { return isMysql; }
    public Map<String, BotRecord> getActiveRecords() { return Collections.unmodifiableMap(activeRecords); }

    // ── Inner types ───────────────────────────────────────────────────────────
    private record PendingLocation(String world, double x, double y, double z, float yaw, float pitch) {}

    /** Row from fpp_active_bots — used for startup restore. */
    public record ActiveBotRow(
            String botUuid, String botName, String botDisplay,
            String spawnedBy, String spawnedByUuid,
            String world, double x, double y, double z,
            float yaw, float pitch,
            String luckpermsGroup,
            String serverId
    ) {}

    /**
     * Snapshot of aggregated database statistics.
     *
     * @param totalSessions    total bot sessions ever recorded
     * @param activeSessions   currently open sessions (no removed_at)
     * @param uniqueBots       distinct bot names ever seen
     * @param uniqueSpawners   distinct players who ever spawned a bot
     * @param totalUptimeMs    sum of all completed session durations in milliseconds
     * @param backend          "MySQL" or "SQLite"
     */
    public record DbStats(
            int    totalSessions,
            int    activeSessions,
            int    uniqueBots,
            int    uniqueSpawners,
            long   totalUptimeMs,
            String backend
    ) {
        /** Total uptime of all bots combined, formatted as {@code Xd Xh Xm}. */
        public String formattedUptime() {
            long secs = totalUptimeMs / 1000;
            long days  = secs / 86400;
            long hours = (secs % 86400) / 3600;
            long mins  = (secs % 3600) / 60;
            if (days > 0)  return days  + "d " + hours + "h " + mins + "m";
            if (hours > 0) return hours + "h " + mins + "m";
            return mins + "m";
        }
    }
}

package me.bill.fakePlayerPlugin.fakeplayer;

import com.destroystokyo.paper.profile.PlayerProfile;
import me.bill.fakePlayerPlugin.database.BotRecord;
import org.bukkit.Location;
import org.bukkit.entity.Entity;
import org.bukkit.entity.Player;

import java.time.Duration;
import java.time.Instant;
import java.util.UUID;

/**
 * Represents a single active fake player.
 *
 * <p><b>NMS Entity System:</b> Each bot is a single NMS {@code ServerPlayer} entity
 * spawned via {@link NmsPlayerSpawner}. The entity appears to clients as a genuine 
 * player with a body, nametag, tab-list entry, and full interaction support (damage, 
 * knockback, death, drowning, mob targeting, etc.).
 *
 * <p><b>Fake Connection:</b> The NMS player is backed by a fake {@code EmbeddedChannel} 
 * connection that discards all outbound packets. The channel uses a discard-proxy
 * (see {@link NmsPlayerSpawner#createDiscardChannel}) to prevent Netty NPEs during
 * server tick flush operations.
 *
 * <p><b>Auth bypass:</b> The player is created directly in JVM memory without a TCP 
 * connection, so the Mojang session server handshake is never triggered.
 */
@SuppressWarnings("unused") // Public API — used by addons and InfoCommand
public final class FakePlayer {

    private final String        name;
    private final PlayerProfile profile;
    private final UUID          uuid;

    private Location   spawnLocation;

    /** The NMS ServerPlayer entity — physics, skin, nametag all in one. */
    private Player     player;

    // ── Metadata ─────────────────────────────────────────────────────────────
    private String    spawnedBy     = "UNKNOWN";
    private UUID      spawnedByUuid = new UUID(0, 0);
    private BotRecord dbRecord;
    private Instant   spawnTime     = Instant.now();

    /**
     * Optional display name shown in the nametag and tab list.
     * When {@code null}, {@link #getName()} is used for display.
     */
    private String displayName = null;

    /**
     * The Minecraft username used for skin resolution.
     * Admin bots: same as {@link #name}.
     * User bots: a random pool name (their internal name has no Mojang skin).
     */
    private String skinName = null;

    /**
     * Optional override for the profile name sent in PlayerInfo packets (tab list).
     * This is used to inject a small, non-visible sort prefix based on LuckPerms
     * group weight so bots can be ordered in the tab list without changing their
     * visible display name or skin lookup source.
     */
    private String packetProfileName = null;

    /**
     * The resolved skin texture (value + signature) for this bot.
     * Populated after async skin resolution. {@code null} if skin mode is "off".
     */
    private SkinProfile resolvedSkin = null;

    // ── Session stats ─────────────────────────────────────────────────────────

    /** Total damage this bot has received during its current session. */
    private double totalDamageTaken = 0.0;

    /** Number of times this bot has been killed. */
    private int    deathCount       = 0;

    /**
     * Last chunk X and Z this bot was in — used by ChunkLoader to
     * detect cross-chunk movement without a Location allocation.
     */
    private int lastChunkX = Integer.MIN_VALUE;
    private int lastChunkZ = Integer.MIN_VALUE;

    /** Whether the bot is currently alive (false after death, until respawn). */
    private boolean alive = true;

    /** How many times this bot has been "tag list refreshed" (diagnostic). */
    private int tabRefreshCount = 0;

    /**
     * Whether this bot is currently frozen in place.
     * Frozen bots have {@code setImmovable(true)} and {@code setGravity(false)};
     * head-AI skips them and they are highlighted in /fpp list & /fpp stats.
     */
    private boolean frozen = false;

    /**
     * Sequential index for user-tier bots (the {@code {num}} placeholder value).
     * Set to {@code -1} for admin-spawned bots.
     * Stored so that {@link me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager#updateAllBotPrefixes()}
     * can correctly rebuild display names after a LuckPerms group change without
     * leaving {@code {spawner}} or {@code {num}} as literal text.
     */
    private int botIndex = -1;

    /** Last world name — used for fast orphan/cross-world detection. */
    private String lastKnownWorld = null;

    /**
     * Optional LuckPerms group override for this specific bot.
     * When set, this bot will use this LP group's prefix and weight instead of
     * the global {@code luckperms.bot-group} config or default group.
     * Set via {@code /fpp rank set <bot> <group>}.
     */
    private String luckpermsGroup = null;

    /**
     * When {@code true}, this bot spawns without a physical body.
     * Used for console-spawned bots with incomplete location data.
     * Bots still appear in tab list and chat, but have no entity in the world.
     */
    private boolean bodyless = false;

    public FakePlayer(UUID uuid, String name, PlayerProfile profile) {
        this.uuid    = uuid;
        this.name    = name;
        this.profile = profile;
    }

    // ── Core getters ──────────────────────────────────────────────────────────
    public UUID          getUuid()          { return uuid; }
    public String        getName()          { return name; }
    public PlayerProfile getProfile()       { return profile; }
    public Location      getSpawnLocation() { return spawnLocation; }

    /** Returns the NMS Player entity (same as {@link #getPlayer()}). */
    public org.bukkit.entity.Player getPhysicsEntity() { 
        return player;
    }

    /** Get the NMS Player entity. */
    public org.bukkit.entity.Player getPlayer() { 
        return player;
    }

    /** 
     * Get the entity ID of the NMS Player entity.
     * Returns -1 if no player entity is set.
     */
    public int getEntityId() { 
        return player != null ? player.getEntityId() : -1; 
    }

    /**
     * The text shown in the nametag and tab list.
     * Falls back to {@link #getName()} when no display name is set.
     */
    public String getDisplayName() { return displayName != null ? displayName : name; }

    /**
     * The Minecraft username used for skin lookup.
     * Falls back to {@link #getName()} if not explicitly set.
     */
    public String getSkinName() { return skinName != null ? skinName : name; }

    /**
     * Returns the most accurate current location for this bot:
     * the live NMS Player body position if available, otherwise the last
     * recorded spawn location.
     */
    public Location getLiveLocation() {
        if (player != null && player.isValid()) return player.getLocation();
        return spawnLocation;
    }

    /**
     * Returns the bot's uptime as a {@link Duration}.
     * Accurate to the second.
     */
    public Duration getUptime() {
        return Duration.between(spawnTime, Instant.now());
    }

    /** Uptime formatted as {@code Xh Ym Zs} for display in /fpp list and /fpp info. */
    public String getUptimeFormatted() {
        Duration d = getUptime();
        long h = d.toHours();
        long m = d.toMinutesPart();
        long s = d.toSecondsPart();
        if (h > 0)  return h + "h " + m + "m " + s + "s";
        if (m > 0)  return m + "m " + s + "s";
        return s + "s";
    }

    // ── Session stats ─────────────────────────────────────────────────────────
    public double getTotalDamageTaken()          { return totalDamageTaken; }
    public int    getDeathCount()                { return deathCount; }
    public boolean isAlive()                     { return alive; }
    public int    getTabRefreshCount()           { return tabRefreshCount; }
    public boolean isFrozen()                    { return frozen; }
    public String getLastKnownWorld()            { return lastKnownWorld; }

    public void addDamageTaken(double amount)    { totalDamageTaken += amount; }
    public void incrementDeathCount()            { deathCount++; }
    public void setAlive(boolean alive)          { this.alive = alive; }
    public void incrementTabRefresh()            { tabRefreshCount++; }
    public void setFrozen(boolean frozen)        { this.frozen = frozen; }
    public int  getBotIndex()                    { return botIndex; }
    public void setBotIndex(int index)           { this.botIndex = index; }

    // ── Chunk tracking (for ChunkLoader fast-path) ────────────────────────────
    public int getLastChunkX()                   { return lastChunkX; }
    public int getLastChunkZ()                   { return lastChunkZ; }
    public void setLastChunk(int cx, int cz)     { lastChunkX = cx; lastChunkZ = cz; }
    public boolean hasMovedChunk(int cx, int cz) { return cx != lastChunkX || cz != lastChunkZ; }

    // ── Core setters ──────────────────────────────────────────────────────────
    public void setSpawnLocation(Location loc)    { this.spawnLocation = loc; }

    /** Set the NMS Player entity. */
    public void setPlayer(org.bukkit.entity.Player p) { this.player = p; }

    /** Set the physics entity (for compatibility — accepts Player or casts to Player). */
    public void setPhysicsEntity(Entity e) { 
        this.player = e instanceof org.bukkit.entity.Player ? (org.bukkit.entity.Player) e : null;
    }

    public void setDisplayName(String name)       { this.displayName   = name; }
    public void setSkinName(String name)          { this.skinName      = name; }
    public void setResolvedSkin(SkinProfile skin) { this.resolvedSkin  = skin; }

    /** The profile name to use when building the GameProfile in tab packets. */
    public String getPacketProfileName() {
        return packetProfileName != null ? packetProfileName : name;
    }

    public void setPacketProfileName(String s) { this.packetProfileName = s; }

    /** The resolved skin for this bot, or {@code null} if not yet resolved or skin is off. */
    public SkinProfile getResolvedSkin()          { return resolvedSkin; }

    // ── Metadata ──────────────────────────────────────────────────────────────
    public String    getSpawnedBy()              { return spawnedBy; }
    public UUID      getSpawnedByUuid()          { return spawnedByUuid; }
    public BotRecord getDbRecord()               { return dbRecord; }
    public Instant   getSpawnTime()              { return spawnTime; }

    public void setSpawnedBy(String name, UUID uuid) {
        this.spawnedBy     = name;
        this.spawnedByUuid = uuid;
    }
    public void setDbRecord(BotRecord record)    { this.dbRecord  = record; }
    public void setSpawnTime(Instant t)          { this.spawnTime = t; }

    // ── LuckPerms group override ──────────────────────────────────────────────
    /**
     * Returns the LuckPerms group override for this bot, or {@code null} if using
     * the global config/default group.
     */
    public String getLuckpermsGroup() { return luckpermsGroup; }

    /**
     * Sets a LuckPerms group override for this bot.
     * Pass {@code null} to clear the override and use global config/default.
     */
    public void setLuckpermsGroup(String group) { this.luckpermsGroup = group; }

    // ── Bodyless spawn ────────────────────────────────────────────────────────
    /**
     * Returns {@code true} if this bot spawns without a physical body
     * (tab-list and chat only, no entity in world).
     */
    public boolean isBodyless() { return bodyless; }

    /**
     * Sets whether this bot should spawn without a physical body.
     * Used for console spawns without location data.
     */
    public void setBodyless(boolean bodyless) { this.bodyless = bodyless; }
}

package me.bill.fakePlayerPlugin.fakeplayer;

import com.destroystokyo.paper.profile.PlayerProfile;
import me.bill.fakePlayerPlugin.database.BotRecord;
import org.bukkit.Location;
import org.bukkit.entity.Entity;
import org.bukkit.entity.Player;

import java.time.Duration;
import java.time.Instant;
import java.util.UUID;

/**
 * Represents a single active fake player.
 *
 * <p><b>NMS Entity System:</b> Each bot is a single NMS {@code ServerPlayer} entity
 * spawned via {@link NmsPlayerSpawner}. The entity appears to clients as a genuine 
 * player with a body, nametag, tab-list entry, and full interaction support (damage, 
 * knockback, death, drowning, mob targeting, etc.).
 *
 * <p><b>Fake Connection:</b> The NMS player is backed by a fake {@code EmbeddedChannel} 
 * connection that discards all outbound packets. The channel uses a discard-proxy
 * (see {@link NmsPlayerSpawner#createDiscardChannel}) to prevent Netty NPEs during
 * server tick flush operations.
 *
 * <p><b>Auth bypass:</b> The player is created directly in JVM memory without a TCP 
 * connection, so the Mojang session server handshake is never triggered.
 */
@SuppressWarnings("unused") // Public API — used by addons and InfoCommand
public final class FakePlayer {

    private final String        name;
    private final PlayerProfile profile;
    private final UUID          uuid;

    private Location   spawnLocation;

    /** The NMS ServerPlayer entity — physics, skin, nametag all in one. */
    private Player     player;

    // ── Metadata ─────────────────────────────────────────────────────────────
    private String    spawnedBy     = "UNKNOWN";
    private UUID      spawnedByUuid = new UUID(0, 0);
    private BotRecord dbRecord;
    private Instant   spawnTime     = Instant.now();

    /**
     * Optional display name shown in the nametag and tab list.
     * When {@code null}, {@link #getName()} is used for display.
     */
    private String displayName = null;

    /**
     * The Minecraft username used for skin resolution.
     * Admin bots: same as {@link #name}.
     * User bots: a random pool name (their internal name has no Mojang skin).
     */
    private String skinName = null;

    /**
     * The resolved skin texture (value + signature) for this bot.
     * Populated after async skin resolution. {@code null} if skin mode is "off".
     */
    private SkinProfile resolvedSkin = null;

    // ── Session stats ─────────────────────────────────────────────────────────

    /** Total damage this bot has received during its current session. */
    private double totalDamageTaken = 0.0;

    /** Number of times this bot has been killed. */
    private int    deathCount       = 0;

    /**
     * Last chunk X and Z this bot was in — used by ChunkLoader to
     * detect cross-chunk movement without a Location allocation.
     */
    private int lastChunkX = Integer.MIN_VALUE;
    private int lastChunkZ = Integer.MIN_VALUE;

    /** Whether the bot is currently alive (false after death, until respawn). */
    private boolean alive = true;

    /** How many times this bot has been "tag list refreshed" (diagnostic). */
    private int tabRefreshCount = 0;

    /**
     * Whether this bot is currently frozen in place.
     * Frozen bots have {@code setImmovable(true)} and {@code setGravity(false)};
     * head-AI skips them and they are highlighted in /fpp list & /fpp stats.
     */
    private boolean frozen = false;

    /**
     * Sequential index for user-tier bots (the {@code {num}} placeholder value).
     * Set to {@code -1} for admin-spawned bots.
     * Stored so that {@link me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager#updateAllBotPrefixes()}
     * can correctly rebuild display names after a LuckPerms group change without
     * leaving {@code {spawner}} or {@code {num}} as literal text.
     */
    private int botIndex = -1;

    /** Last world name — used for fast orphan/cross-world detection. */
    private String lastKnownWorld = null;

    /**
     * Optional LuckPerms group override for this specific bot.
     * When set, this bot will use this LP group's prefix and weight instead of
     * the global {@code luckperms.bot-group} config or default group.
     * Set via {@code /fpp rank set <bot> <group>}.
     */
    private String luckpermsGroup = null;

    /**
     * When {@code true}, this bot spawns without a physical body.
     * Used for console-spawned bots with incomplete location data.
     * Bots still appear in tab list and chat, but have no entity in the world.
     */
    private boolean bodyless = false;

    public FakePlayer(UUID uuid, String name, PlayerProfile profile) {
        this.uuid    = uuid;
        this.name    = name;
        this.profile = profile;
    }

    // ── Core getters ──────────────────────────────────────────────────────────
    public UUID          getUuid()          { return uuid; }
    public String        getName()          { return name; }
    public PlayerProfile getProfile()       { return profile; }
    public Location      getSpawnLocation() { return spawnLocation; }

    /** Returns the NMS Player entity (same as {@link #getPlayer()}). */
    public org.bukkit.entity.Player getPhysicsEntity() { 
        return player;
    }

    /** Get the NMS Player entity. */
    public org.bukkit.entity.Player getPlayer() { 
        return player;
    }

    /** 
     * Get the entity ID of the NMS Player entity.
     * Returns -1 if no player entity is set.
     */
    public int getEntityId() { 
        return player != null ? player.getEntityId() : -1; 
    }

    /**
     * The text shown in the nametag and tab list.
     * Falls back to {@link #getName()} when no display name is set.
     */
    public String getDisplayName() { return displayName != null ? displayName : name; }

    /**
     * The Minecraft username used for skin lookup.
     * Falls back to {@link #getName()} if not explicitly set.
     */
    public String getSkinName() { return skinName != null ? skinName : name; }

    /**
     * Returns the most accurate current location for this bot:
     * the live NMS Player body position if available, otherwise the last
     * recorded spawn location.
     */
    public Location getLiveLocation() {
        if (player != null && player.isValid()) return player.getLocation();
        return spawnLocation;
    }

    /**
     * Returns the bot's uptime as a {@link Duration}.
     * Accurate to the second.
     */
    public Duration getUptime() {
        return Duration.between(spawnTime, Instant.now());
    }

    /** Uptime formatted as {@code Xh Ym Zs} for display in /fpp list and /fpp info. */
    public String getUptimeFormatted() {
        Duration d = getUptime();
        long h = d.toHours();
        long m = d.toMinutesPart();
        long s = d.toSecondsPart();
        if (h > 0)  return h + "h " + m + "m " + s + "s";
        if (m > 0)  return m + "m " + s + "s";
        return s + "s";
    }

    // ── Session stats ─────────────────────────────────────────────────────────
    public double getTotalDamageTaken()          { return totalDamageTaken; }
    public int    getDeathCount()                { return deathCount; }
    public boolean isAlive()                     { return alive; }
    public int    getTabRefreshCount()           { return tabRefreshCount; }
    public boolean isFrozen()                    { return frozen; }
    public String getLastKnownWorld()            { return lastKnownWorld; }

    public void addDamageTaken(double amount)    { totalDamageTaken += amount; }
    public void incrementDeathCount()            { deathCount++; }
    public void setAlive(boolean alive)          { this.alive = alive; }
    public void incrementTabRefresh()            { tabRefreshCount++; }
    public void setFrozen(boolean frozen)        { this.frozen = frozen; }
    public int  getBotIndex()                    { return botIndex; }
    public void setBotIndex(int index)           { this.botIndex = index; }

    // ── Chunk tracking (for ChunkLoader fast-path) ────────────────────────────
    public int getLastChunkX()                   { return lastChunkX; }
    public int getLastChunkZ()                   { return lastChunkZ; }
    public void setLastChunk(int cx, int cz)     { lastChunkX = cx; lastChunkZ = cz; }
    public boolean hasMovedChunk(int cx, int cz) { return cx != lastChunkX || cz != lastChunkZ; }

    // ── Core setters ──────────────────────────────────────────────────────────
    public void setSpawnLocation(Location loc)    { this.spawnLocation = loc; }

    /** Set the NMS Player entity. */
    public void setPlayer(org.bukkit.entity.Player p) { this.player = p; }

    /** Set the physics entity (for compatibility — accepts Player or casts to Player). */
    public void setPhysicsEntity(Entity e) { 
        this.player = e instanceof org.bukkit.entity.Player ? (org.bukkit.entity.Player) e : null;
    }

    public void setDisplayName(String name)       { this.displayName   = name; }
    public void setSkinName(String name)          { this.skinName      = name; }
    public void setResolvedSkin(SkinProfile skin) { this.resolvedSkin  = skin; }

    /** The profile name to use when building the GameProfile in tab packets. */
    public String getPacketProfileName() {
        return packetProfileName != null ? packetProfileName : name;
    }

    public void setPacketProfileName(String s) { this.packetProfileName = s; }

    /** The resolved skin for this bot, or {@code null} if not yet resolved or skin is off. */
    public SkinProfile getResolvedSkin()          { return resolvedSkin; }

    // ── Metadata ──────────────────────────────────────────────────────────────
    public String    getSpawnedBy()              { return spawnedBy; }
    public UUID      getSpawnedByUuid()          { return spawnedByUuid; }
    public BotRecord getDbRecord()               { return dbRecord; }
    public Instant   getSpawnTime()              { return spawnTime; }

    public void setSpawnedBy(String name, UUID uuid) {
        this.spawnedBy     = name;
        this.spawnedByUuid = uuid;
    }
    public void setDbRecord(BotRecord record)    { this.dbRecord  = record; }
    public void setSpawnTime(Instant t)          { this.spawnTime = t; }

    // ── LuckPerms group override ──────────────────────────────────────────────
    /**
     * Returns the LuckPerms group override for this bot, or {@code null} if using
     * the global config/default group.
     */
    public String getLuckpermsGroup() { return luckpermsGroup; }

    /**
     * Sets a LuckPerms group override for this bot.
     * Pass {@code null} to clear the override and use global config/default.
     */
    public void setLuckpermsGroup(String group) { this.luckpermsGroup = group; }

    // ── Bodyless spawn ────────────────────────────────────────────────────────
    /**
     * Returns {@code true} if this bot spawns without a physical body
     * (tab-list and chat only, no entity in world).
     */
    public boolean isBodyless() { return bodyless; }

    /**
     * Sets whether this bot should spawn without a physical body.
     * Used for console spawns without location data.
     */
    public void setBodyless(boolean bodyless) { this.bodyless = bodyless; }
}

package me.bill.fakePlayerPlugin.listener;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.BotBroadcast;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayer;
import me.bill.fakePlayerPlugin.fakeplayer.ChunkLoader;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerBody;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import me.bill.fakePlayerPlugin.fakeplayer.PacketHelper;
import net.kyori.adventure.text.Component;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.Sound;
import org.bukkit.SoundCategory;
import org.bukkit.entity.Entity;
import org.bukkit.entity.Player;
import org.bukkit.event.EventHandler;
import org.bukkit.event.EventPriority;
import org.bukkit.event.Listener;
import org.bukkit.event.entity.EntityDamageEvent;
import org.bukkit.event.entity.EntityDeathEvent;
import org.bukkit.event.entity.EntityPortalEvent;
import org.bukkit.event.entity.EntityTeleportEvent;
import org.bukkit.persistence.PersistentDataType;

public class FakePlayerEntityListener implements Listener {

    private final FakePlayerPlugin  plugin;
    private final FakePlayerManager manager;
    private final ChunkLoader       chunkLoader;

    public FakePlayerEntityListener(FakePlayerPlugin plugin, FakePlayerManager manager, ChunkLoader chunkLoader) {
        this.plugin      = plugin;
        this.manager     = manager;
        this.chunkLoader = chunkLoader;
    }

    // ── Damage filter ─────────────────────────────────────────────────────────

    @EventHandler(priority = EventPriority.LOWEST)
    public void onEntityDamage(EntityDamageEvent event) {
        if (!isFakeBotBody(event.getEntity())) return;

        // Primary damageable guard — event-level cancellation beats any entity flag.
        // Checked live from config so /fpp reload takes effect without respawn.
        if (!Config.bodyDamageable()) {
            event.setCancelled(true);
            return;
        }

        // Cancel damage types that shouldn't affect a player-like entity
        switch (event.getCause()) {
            case VOID, SUFFOCATION, CRAMMING,
                 STARVATION, FREEZE, MELTING,
                 FLY_INTO_WALL, DRYOUT,
                 POISON, WITHER, MAGIC,
                 LIGHTNING -> {
                event.setCancelled(true);
                return;
            }
            default -> {}
        }

        // Track damage for statistics
        if (!event.isCancelled() && event.getEntity() instanceof Player p) {
            FakePlayer fp = manager.getByEntity(p);
            if (fp != null) {
                fp.addDamageTaken(event.getFinalDamage());
            }
        }

        // Play player hurt sound
        if (Config.hurtSound()) {
            Location loc = event.getEntity().getLocation();
            for (Player p : Bukkit.getOnlinePlayers())
                p.playSound(loc, Sound.ENTITY_PLAYER_HURT, SoundCategory.PLAYERS, 1.0f, 1.0f);
        }
    }

    // ── Portal / teleport guard ───────────────────────────────────────────────

    /**
     * Prevents bot Mannequin bodies from traversing portals.
     *
     * <p>When an entity goes through a portal Minecraft ejects its passengers
     * (the ArmorStand nametag) at the portal entrance, orphaning it in the
     * original world.  The entity also receives a new entity-id in the target
     * world, breaking {@code entityIdIndex} lookups and causing the death
     * handler to silently skip cleanup.  Blocking the portal event prevents
     * all of these cascading issues.
     */
    @EventHandler(priority = EventPriority.NORMAL, ignoreCancelled = true)
    public void onEntityPortal(EntityPortalEvent event) {
        if (!isFakeBotBody(event.getEntity())) return;
        event.setCancelled(true);
        Config.debug("Blocked portal traversal for bot body: "
                + event.getEntity().getPersistentDataContainer()
                        .get(FakePlayerManager.FAKE_PLAYER_KEY, PersistentDataType.STRING));
    }

    /**
     * Prevents bot Mannequin bodies from being teleported to a different world
     * via commands, plugins, or other mechanics (chorus fruit, etc.).
     *
     * <p>Same root cause as the portal case: cross-world teleports eject
     * passengers and break the entity-id index.  Same-world teleports are
     * allowed (they don't change the entity id or eject riders).
     */
    @EventHandler(priority = EventPriority.NORMAL, ignoreCancelled = true)
    public void onEntityTeleport(EntityTeleportEvent event) {
        if (!isFakeBotBody(event.getEntity())) return;
        org.bukkit.Location from = event.getFrom();
        org.bukkit.Location to   = event.getTo();
        if (to == null || from.getWorld() == null || to.getWorld() == null) return;
        if (from.getWorld().equals(to.getWorld())) return; // same world — fine
        event.setCancelled(true);
        Config.debug("Blocked cross-world teleport for bot body: "
                + event.getEntity().getPersistentDataContainer()
                        .get(FakePlayerManager.FAKE_PLAYER_KEY, PersistentDataType.STRING));
    }

    // ── Death ─────────────────────────────────────────────────────────────────

    @EventHandler(priority = EventPriority.MONITOR)
    public void onEntityDeath(EntityDeathEvent event) {
        if (!isFakeBotBody(event.getEntity())) return;

        if (Config.suppressDrops()) {
            event.getDrops().clear();
            event.setDroppedExp(0);
        }

        FakePlayer fp = manager.getByEntity(event.getEntity());
        if (fp == null) return;

        Player killer = event.getEntity().getKiller();
        if (killer != null) {
            BotBroadcast.broadcastKill(killer.getName(), fp.getDisplayName());
        }

        // Increment death counter
        fp.incrementDeathCount();
        fp.setAlive(false);

        final Location respawnLoc = fp.getSpawnLocation() != null
                ? fp.getSpawnLocation().clone()
                : event.getEntity().getLocation().clone();
        final String name        = fp.getName();
        final String displayName = fp.getDisplayName();

        // Remove the dead player entity after the death animation (~1 second)
        if (event.getEntity() instanceof Player deadPlayer) {
            Bukkit.getScheduler().runTaskLater(plugin, () -> {
                if (deadPlayer.isOnline()) {
                    deadPlayer.kick(Component.empty());
                }
            }, 20L);
        }

        // Clear references
        fp.setPlayer(null);
        manager.removeFromEntityIndex(event.getEntity().getEntityId());

        if (Config.respawnOnDeath()) {
            int delay = Math.max(20, Config.respawnDelay()); // Minimum 1 second
            if (chunkLoader != null) chunkLoader.releaseForBot(fp);

            Bukkit.getScheduler().runTaskLater(plugin, () -> {
                // Remove from tab list while dead
                for (Player p : Bukkit.getOnlinePlayers()) PacketHelper.sendTabListRemove(p, fp);

                // Respawn the bot with a new NMS ServerPlayer entity
                if (Config.spawnBody()) {
                    Player newBody = FakePlayerBody.spawn(fp, respawnLoc);
                    if (newBody == null) {
                        // Spawn failed — bot already kicked, vanilla quit message shown
                        manager.removeByName(name);
                        return;
                    }
                    fp.setPlayer(newBody);
                    fp.setAlive(true);
                    manager.registerEntityIndex(newBody.getEntityId(), fp);

                    // Re-add to tab list after respawn
                    Bukkit.getScheduler().runTaskLater(plugin, () -> {
                        if (Config.tabListEnabled())
                            for (Player p : Bukkit.getOnlinePlayers())
                                PacketHelper.sendTabListAdd(p, fp);
                    }, 5L);
                } else {
                    // Body disabled but bot should "respawn" — re-add to tab list
                    fp.setAlive(true);
                    if (Config.tabListEnabled())
                        for (Player p : Bukkit.getOnlinePlayers())
                            PacketHelper.sendTabListAdd(p, fp);
                }

                fp.setSpawnLocation(respawnLoc);
            }, delay);

        } else {
            if (chunkLoader != null) chunkLoader.releaseForBot(fp);
            Bukkit.getScheduler().runTaskLater(plugin, () -> {
                for (Player p : Bukkit.getOnlinePlayers()) PacketHelper.sendTabListRemove(p, fp);
                broadcastLeave(displayName);
                manager.removeByName(name);
            }, 20L); // 1 second delay
        }
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    private void broadcastLeave(String displayName) {
        BotBroadcast.broadcastLeaveByDisplayName(displayName);
    }

    /** True only for Player entities tagged as an FPP bot. */
    private boolean isFakeBotBody(Entity entity) {
        if (!(entity instanceof Player)) return false;
        if (FakePlayerManager.FAKE_PLAYER_KEY == null) return false;
        String val = entity.getPersistentDataContainer()
                .get(FakePlayerManager.FAKE_PLAYER_KEY, PersistentDataType.STRING);
        return val != null && val.startsWith(FakePlayerBody.VISUAL_PDC_VALUE);
    }
}

package me.bill.fakePlayerPlugin.listener;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.BotBroadcast;
