            Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text("ᴘᴀɢᴇ ᴛᴏ ᴛʜᴇɪʀ ᴅᴇꜰᴀᴜʟᴛ ᴠᴀʟᴜᴇꜱ.").color(GRAY))));
