    private Category peaks() {
        return new Category("⏰ ᴘᴇᴀᴋ ʜᴏᴜʀꜱ",
            Material.DAYLIGHT_DETECTOR, Material.COMPARATOR,
            Material.ORANGE_STAINED_GLASS_PANE,
            List.of(
                SettingEntry.toggle("peak-hours.enabled",            "ᴘᴇᴀᴋ ʜᴏᴜʀꜱ",
