                SettingEntry.toggle("swap.farewell-chat",       "ꜰᴀʀᴇᴡᴇʟʟ ᴍᴇꜱꜱᴀɢᴇꜱ",
                    "ʙᴏᴛꜱ ꜱᴀʏ ɢᴏᴏᴅʙʏᴇ ʙᴇꜰᴏʀᴇ\nʟᴇᴀᴠɪɴɢ ᴛʜᴇ ꜱᴇʀᴠᴇʀ.",
                    Material.POPPY),
                SettingEntry.toggle("swap.greeting-chat",       "ɢʀᴇᴇᴛɪɴɢ ᴍᴇꜱꜱᴀɢᴇꜱ",
                    "ʙᴏᴛꜱ ɢʀᴇᴇᴛ ᴛʜᴇ ꜱᴇʀᴠᴇʀ\nᴡʜᴇɴ ᴛʜᴇʏ ʀᴇᴛᴜʀɴ.",
                    Material.DANDELION),
                SettingEntry.toggle("swap.same-name-on-rejoin", "ᴋᴇᴇᴘ ɴᴀᴍᴇ ᴏɴ ʀᴇᴊᴏɪɴ",
                    "ʙᴏᴛꜱ ᴛʀʏ ᴛᴏ ʀᴇᴄʟᴀɪᴍ ᴛʜᴇɪʀ\nᴏʀɪɢɪɴᴀʟ ɴᴀᴍᴇ ᴡʜᴇɴ ʀᴇᴛᴜʀɴɪɴɢ.",
                    Material.NAME_TAG),
                SettingEntry.cycleInt("swap.session.min",       "ꜱᴇꜱꜱɪᴏɴ — ᴍɪɴ (ꜱ)",
                    "ꜱʜᴏʀᴛᴇꜱᴛ ᴘᴏꜱꜱɪʙʟᴇ ᴛɪᴍᴇ ᴀ\nʙᴏᴛ ꜱᴛᴀʏꜱ ᴏɴʟɪɴᴇ.",
                    Material.CLOCK, new int[]{ 30, 60, 120, 300, 600 }),
                SettingEntry.cycleInt("swap.session.max",       "ꜱᴇꜱꜱɪᴏɴ — ᴍᴀx (ꜱ)",
                    "ʟᴏɴɢᴇꜱᴛ ᴘᴏꜱꜱɪʙʟᴇ ᴛɪᴍᴇ ᴀ\nʙᴏᴛ ꜱᴛᴀʏꜱ ᴏɴʟɪɴᴇ.",
                    Material.CLOCK, new int[]{ 60, 120, 300, 600, 1200 }),
                SettingEntry.cycleInt("swap.absence.min",       "ᴀʙꜱᴇɴᴄᴇ — ᴍɪɴ (ꜱ)",
                    "ꜱʜᴏʀᴛᴇꜱᴛ ᴛɪᴍᴇ ᴀ ʙᴏᴛ\nꜱᴘᴇɴᴅꜱ ᴏꜰꜰʟɪɴᴇ.",
                    Material.GRAY_DYE, new int[]{ 15, 30, 60, 120 }),
                SettingEntry.cycleInt("swap.absence.max",       "ᴀʙꜱᴇɴᴄᴇ — ᴍᴀx (ꜱ)",
                    "ʟᴏɴɢᴇꜱᴛ ᴛɪᴍᴇ ᴀ ʙᴏᴛ\nꜱᴘᴇɴᴅꜱ ᴏꜰꜰʟɪɴᴇ.",
                    Material.GRAY_DYE, new int[]{ 30, 60, 120, 300 }),
                SettingEntry.cycleInt("swap.max-swapped-out",   "ᴍᴀx ᴏꜰꜰʟɪɴᴇ ᴀᴛ ᴏɴᴄᴇ",
                    "ᴄᴀᴘ ᴏɴ ꜱɪᴍᴜʟᴛᴀɴᴇᴏᴜꜱʟʏ ᴀʙꜱᴇɴᴛ\nʙᴏᴛꜱ. 0 = ᴜɴʟɪᴍɪᴛᴇᴅ.",
                    Material.HOPPER, new int[]{ 0, 1, 2, 3, 5, 10 })
            ));
    }

    private Category peaks() {
        return new Category("⏰ ᴘᴇᴀᴋ ʜᴏᴜʀꜱ",
            Material.DAYLIGHT_DETECTOR, Material.COMPARATOR,
            Material.ORANGE_STAINED_GLASS_PANE,
            List.of(
                SettingEntry.toggle("peak-hours.enabled",            "ᴘᴇᴀᴋ ʜᴏᴜʀꜱ",
                    "ꜱᴄᴀʟᴇ ʙᴏᴛ ᴄᴏᴜɴᴛ ʙʏ ᴛɪᴍᴇ ᴡɪɴᴅᴏᴡ.\nʀᴇQᴜɪʀᴇꜱ ꜱᴡᴀᴘ ᴛᴏ ʙᴇ ᴇɴᴀʙʟᴇᴅ.",
                    Material.DAYLIGHT_DETECTOR),
                SettingEntry.toggle("peak-hours.notify-transitions", "ɴᴏᴛɪꜰʏ ᴛʀᴀɴꜱɪᴛɪᴏɴꜱ",
                    "ᴀʟᴇʀᴛ ꜰᴘᴘ.ᴘᴇᴀᴋꜱ ᴀᴅᴍɪɴꜱ ᴡʜᴇɴ\nᴛʜᴇ ᴀᴄᴛɪᴠᴇ ᴡɪɴᴅᴏᴡ ᴄʜᴀɴɢᴇꜱ.",
                    Material.BELL),
                SettingEntry.cycleInt("peak-hours.min-online",       "ᴍɪɴ ʙᴏᴛꜱ ᴏɴʟɪɴᴇ",
                    "ꜰʟᴏᴏʀ: ᴍɪɴɪᴍᴜᴍ ᴀᴄᴛɪᴠᴇ ʙᴏᴛꜱ\nʀᴇɢᴀʀᴅʟᴇꜱꜱ ᴏꜰ ꜰʀᴀᴄᴛɪᴏɴ. 0 = ᴏꜰꜰ.",
                    Material.COMPARATOR, new int[]{ 0, 1, 2, 5, 10 }),
                SettingEntry.cycleInt("peak-hours.stagger-seconds",  "ᴛʀᴀɴꜱɪᴛɪᴏɴ ꜱᴛᴀɢɢᴇʀ (ꜱ)",
                    "ꜱᴘʀᴇᴀᴅ ʙᴏᴛ ᴊᴏɪɴ/ʟᴇᴀᴠᴇ ᴇᴠᴇɴᴛꜱ\nᴀᴄʀᴏꜱꜱ ᴛʜɪꜱ ᴡɪɴᴅᴏᴡ ɪɴ ꜱᴇᴄᴏɴᴅꜱ.",
                    Material.CLOCK, new int[]{ 5, 10, 30, 60, 120 })
            ));
    }

    // ═════════════════════════════════════════════════════════════════════════
    //  Inner types
    // ═════════════════════════════════════════════════════════════════════════

    /** Tags our inventories so the event handler can identify them quickly. */
    private static final class GuiHolder implements InventoryHolder {
        final UUID uuid;
        GuiHolder(UUID uuid) { this.uuid = uuid; }
        @SuppressWarnings("NullableProblems")
        @Override public Inventory getInventory() { return null; }
    }

    private record Category(
        String label, Material activeMat, Material inactiveMat,
        Material separatorGlass, List<SettingEntry> settings
    ) {}

    private enum SettingType { TOGGLE, CYCLE_INT, CYCLE_DOUBLE, COMING_SOON }

    /**
     * Tracks an in-progress chat-input session for a single player.
     *
     * @param entry         the setting being edited
     * @param guiState      [categoryIndex, pageIndex] to restore when done
     * @param cleanupTaskId Bukkit task ID for the 60-second safety cleanup
     */
    private record ChatInputSession(
        SettingEntry entry,
        int[]        guiState,
        int          cleanupTaskId
    ) {}

    private static final class SettingEntry {
        final String      configKey;
        final String      label;
        final String      description;
        final Material    icon;
        final SettingType type;
        final int[]       intValues;
        final double[]    dblValues;

        private SettingEntry(String configKey, String label, String description,
                             Material icon, SettingType type,
                             int[] intValues, double[] dblValues) {
            this.configKey   = configKey;
            this.label       = label;
            this.description = description;
            this.icon        = icon;
            this.type        = type;
            this.intValues   = intValues;
            this.dblValues   = dblValues;
        }

        static SettingEntry toggle(String key, String label, String desc, Material icon) {
            return new SettingEntry(key, label, desc, icon,
                    SettingType.TOGGLE, null, null);
        }

        static SettingEntry cycleInt(String key, String label, String desc,
                                     Material icon, int[] values) {
            return new SettingEntry(key, label, desc, icon,
                    SettingType.CYCLE_INT, values, null);
        }

        static SettingEntry cycleDouble(String key, String label, String desc,
                                        Material icon, double[] values) {
            return new SettingEntry(key, label, desc, icon,
                    SettingType.CYCLE_DOUBLE, null, values);
        }

        /** Creates a locked "coming soon" entry — clicking plays ENTITY_VILLAGER_NO. */
        static SettingEntry comingSoon(String key, String label, String desc, Material icon) {
            return new SettingEntry(key, label, desc, icon,
                    SettingType.COMING_SOON, null, null);
        }

        String currentValueString(FakePlayerPlugin plugin) {
            var cfg = plugin.getConfig();
            return switch (type) {
                case TOGGLE       -> cfg.getBoolean(configKey, false) ? "✔ ᴇɴᴀʙʟᴇᴅ" : "✘ ᴅɪꜱᴀʙʟᴇᴅ";
                case CYCLE_INT    -> String.valueOf(cfg.getInt(configKey, intValues[0]));
                case CYCLE_DOUBLE -> {
                    double d = cfg.getDouble(configKey, dblValues[0]);
                    yield (d == Math.floor(d) && !Double.isInfinite(d))
                            ? String.valueOf((int) d)
                            : String.format("%.2f", d);
                }
                case COMING_SOON  -> "⚠ ᴄᴏᴍɪɴɢ ꜱᴏᴏɴ";
            };
        }

        /** Flips the boolean config value in place.  Used only for TOGGLE entries. */
        void apply(FakePlayerPlugin plugin) {
            if (type == SettingType.TOGGLE) {
                plugin.getConfig().set(configKey, !plugin.getConfig().getBoolean(configKey, false));
            }
        }
    }
}

package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.World;
import org.bukkit.command.CommandSender;
import org.bukkit.entity.Player;

import java.util.ArrayList;
import java.util.List;

/**
 * {@code /fpp spawn [amount] [--name <name>] [--world <world> [x,y,z]]} — spawns one or more fake players.
 *
 * <h3>Tiers</h3>
 * <ul>
 *   <li><b>Admin</b> ({@code fpp.spawn}) — unlimited count (up to max-bots), optional
 *       {@code --name} flag ({@code fpp.spawn.name}), spawning multiple at once
 *       ({@code fpp.spawn.multiple}). Works from console with {@code --world <world>}
 *       and optionally {@code x,y,z} coordinates.</li>
 *   <li><b>Console</b> — from console, use:
 *       <ul>
 *         <li>{@code /fpp spawn 5} — spawns without body (tab-list only)</li>
 *         <li>{@code /fpp spawn 5 world} — spawns at world spawn location with body</li>
 *         <li>{@code /fpp spawn 5 world 100,64,200} — spawns at specific location with body</li>
 *       </ul>
 *       If no world is specified from console, bot spawns without physical body.</li>
 *   <li><b>User</b> ({@code fpp.user.spawn}) — limited by personal bot limit resolved
 *       from {@code fpp.bot.<n>} permission nodes; falls back to
 *       {@code limits.user-bot-limit} in config. Subject to spawn cooldown unless
 *       {@code fpp.bypass.cooldown} is set.</li>
 * </ul>
 */
@SuppressWarnings("unused") // Registered dynamically via CommandManager.register()
public class SpawnCommand implements FppCommand {

    private final FakePlayerManager manager;

    public SpawnCommand(FakePlayerManager manager) {
        this.manager = manager;
    }

    @Override public String getName()        { return "spawn"; }
    @Override public String getUsage()       { return "[amount] [world [x,y,z]]"; }
    @Override public String getDescription() { return "Spawns one or more fake player bots."; }
    @Override public String getPermission()  { return Perm.SPAWN; }

    /** Both admin-spawn and user-spawn are accepted. */
    @Override
    public boolean canUse(CommandSender sender) {
        return Perm.has(sender, Perm.SPAWN) || Perm.has(sender, Perm.USER_SPAWN);
    }

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        boolean isAdmin = Perm.has(sender, Perm.SPAWN);
        boolean isUser  = !isAdmin && Perm.has(sender, Perm.USER_SPAWN);

        if (!isAdmin && !isUser) {
            sender.sendMessage(Lang.get("no-permission"));
            return true;
        }

        // ── Parse arguments ───────────────────────────────────────────────────
        int    count      = 1;
        String customName = null;
        String worldName  = null;
        double coordX     = 0;
        double coordY     = 0;
        double coordZ     = 0;
        boolean spawnWithoutBody = false;

        boolean isConsole = !(sender instanceof Player);

        // Parse arguments differently for console vs player
        if (isConsole) {
            // Console syntax: /fpp spawn [count] [world [x,y,z]]
            // e.g., /fpp spawn 5
            // e.g., /fpp spawn 5 world
            // e.g., /fpp spawn 5 world 100,64,200
            if (args.length >= 1) {
                try {
                    count = Integer.parseInt(args[0]);
                    if (count <= 0) throw new NumberFormatException();
                } catch (NumberFormatException e) {
                    sender.sendMessage(Lang.get("spawn-invalid"));
                    return true;
                }
            }
            if (args.length >= 2) {
                worldName = args[1];
                World w = Bukkit.getWorld(worldName);
                if (w == null) {
                    sender.sendMessage(Lang.get("spawn-world-not-found", "world", worldName));
                    return true;
                }
            } else {
                // No world specified from console — spawn without body (tab-list only)
                spawnWithoutBody = true;
            }
            if (args.length >= 3) {
                // Parse x,y,z coordinates
                String coordStr = args[2];
                String[] coords = coordStr.split(",");
                if (coords.length != 3) {
                    sender.sendMessage(Lang.get("spawn-invalid-coords"));
                    return true;
                }
                try {
                    coordX = Double.parseDouble(coords[0]);
                    coordY = Double.parseDouble(coords[1]);
                    coordZ = Double.parseDouble(coords[2]);
                } catch (NumberFormatException e) {
                    sender.sendMessage(Lang.get("spawn-invalid-coords"));
                    return true;
                }
            }
        } else {
            // Player syntax: /fpp spawn [amount] [--name <name>] [--world <world>]
            for (int i = 0; i < args.length; i++) {
                switch (args[i].toLowerCase()) {
                    case "--name" -> {
                        if (i + 1 < args.length) {
                            customName = args[++i];
                        } else {
                            sender.sendMessage(Lang.get("spawn-invalid"));
                            return true;
                        }
                    }
                    case "--world" -> {
                        if (i + 1 < args.length) {
                            worldName = args[++i];
                        } else {
                            sender.sendMessage(Lang.get("spawn-invalid"));
                            return true;
                        }
                    }
                    default -> {
                        try {
                            count = Integer.parseInt(args[i]);
                            if (count <= 0) throw new NumberFormatException();
                        } catch (NumberFormatException e) {
                            sender.sendMessage(Lang.get("spawn-invalid"));
                            return true;
                        }
                    }
                }
            }
        }

        // ── Resolve spawn location ─────────────────────────────────────────────
        Location location;
        if (sender instanceof Player player) {
            location = player.getLocation();
            if (worldName != null) {
                World w = Bukkit.getWorld(worldName);
                if (w == null) {
                    sender.sendMessage(Lang.get("spawn-world-not-found", "world", worldName));
                    return true;
                }
                location = w.getSpawnLocation();
            }
        } else {
            // Console spawn
            if (worldName != null) {
                World w = Bukkit.getWorld(worldName);
                if (w == null) {
                    sender.sendMessage(Lang.get("spawn-world-not-found", "world", worldName));
                    return true;
                }
                // Use custom coordinates if provided, otherwise world spawn
                if (args.length >= 3) {
                    location = new Location(w, coordX, coordY, coordZ);
                } else {
                    location = w.getSpawnLocation();
                }
            } else {
                List<World> worlds = Bukkit.getWorlds();
                if (worlds.isEmpty()) {
                    sender.sendMessage(Lang.get("spawn-console-no-world"));
                    return true;
                }
                // Spawn without body — use dummy location (won't be used for body spawning)
                location = worlds.getFirst().getSpawnLocation();
            }
        }

        // ── User-tier spawn ────────────────────────────────────────────────────
        if (isUser) {
            if (!(sender instanceof Player player)) {
                sender.sendMessage(Lang.get("player-only"));
                return true;
            }

            // Cooldown check
            if (!Perm.has(sender, Perm.BYPASS_COOLDOWN) && manager.isOnCooldown(player.getUniqueId())) {
                long remaining = manager.getRemainingCooldown(player.getUniqueId());
                sender.sendMessage(Lang.get("spawn-cooldown", "seconds", String.valueOf(remaining)));
                return true;
            }

            // Enforce personal bot limit
            int permLimit    = Perm.resolveUserBotLimit(sender);
            int limit        = permLimit >= 0 ? permLimit : Config.userBotLimit();
            int alreadyOwned = manager.getBotsOwnedBy(player.getUniqueId()).size();
            if (alreadyOwned >= limit) {
                sender.sendMessage(Lang.get("spawn-user-limit-reached", "limit", String.valueOf(limit)));
                return true;
            }
            count = Math.min(count, limit - alreadyOwned);

            int result = manager.spawnUserBot(location, count, player, false);
            if (result == -1) {
                int max = Config.maxBots();
                sender.sendMessage(Lang.get("spawn-max-reached", "max", String.valueOf(max)));
                return true;
            }
            if (result <= 0) {
                sender.sendMessage(Lang.get("spawn-no-names-left"));
                return true;
            }

            manager.recordSpawnCooldown(player.getUniqueId());
            int total = manager.getCount();
            sender.sendMessage(Lang.get("spawn-success",
                    "count", String.valueOf(result),
                    "total", String.valueOf(total)));
            return true;
        }

        // ── Admin-tier spawn ───────────────────────────────────────────────────

        // Cooldown check (admins also subject to cooldown unless bypassed)
        if (sender instanceof Player player
                && !Perm.has(sender, Perm.BYPASS_COOLDOWN)
                && manager.isOnCooldown(player.getUniqueId())) {
            long remaining = manager.getRemainingCooldown(player.getUniqueId());
            sender.sendMessage(Lang.get("spawn-cooldown", "seconds", String.valueOf(remaining)));
            return true;
        }

        // Multiple bots — check sub-permission
        if (count > 1 && !Perm.has(sender, Perm.SPAWN_MULTIPLE)) {
            sender.sendMessage(Lang.get("no-permission"));
            return true;
        }

        // Custom name — check sub-permission
        if (customName != null && !Perm.has(sender, Perm.SPAWN_CUSTOM_NAME)) {
            sender.sendMessage(Lang.get("no-permission"));
            return true;
        }

        boolean bypassMax = Perm.has(sender, Perm.BYPASS_MAX);
        Player  spawner   = (sender instanceof Player p) ? p : null;

        int result = manager.spawn(location, count, spawner, customName, bypassMax);

        switch (result) {
            case -1 -> {
                int max = Config.maxBots();
                sender.sendMessage(Lang.get("spawn-max-reached", "max", String.valueOf(max)));
            }
            case -2 -> sender.sendMessage(Lang.get("spawn-invalid-name"));
            case 0 -> {
                if (customName != null) {
                    sender.sendMessage(Lang.get("spawn-name-taken", "name", customName));
                } else {
                    sender.sendMessage(Lang.get("spawn-no-names-left"));
                }
            }
            default -> {
                if (sender instanceof Player p) {
                    manager.recordSpawnCooldown(p.getUniqueId());
                }
                int total = manager.getCount();
                sender.sendMessage(Lang.get("spawn-success",
                        "count", String.valueOf(result),
                        "total", String.valueOf(total)));
            }
        }
        return true;
    }

    @Override
    public List<String> tabComplete(CommandSender sender, String[] args) {
        if (!canUse(sender)) return List.of();

        boolean isAdmin = Perm.has(sender, Perm.SPAWN);
        List<String> suggestions = new ArrayList<>();

        if (args.length == 1) {
            String typed = args[0].toLowerCase();
            if (isAdmin) {
                Config.spawnCountPresetsAdmin().stream()
                        .filter(s -> s.startsWith(typed))
                        .forEach(suggestions::add);
            } else {
                int permLimit = Perm.resolveUserBotLimit(sender);
                int limit     = permLimit >= 0 ? permLimit : Config.userBotLimit();
                for (int i = 1; i <= Math.min(limit, 10); i++) {
                    String s = String.valueOf(i);
                    if (s.startsWith(typed)) suggestions.add(s);
                }
            }
            if (isAdmin && "--name".startsWith(typed)) suggestions.add("--name");
            if ("--world".startsWith(typed) && !(sender instanceof Player)) suggestions.add("--world");
        } else if (args.length >= 2) {
            String prev  = args[args.length - 2].toLowerCase();
            String typed = args[args.length - 1].toLowerCase();
            if (prev.equals("--world")) {
                Bukkit.getWorlds().stream()
                        .map(World::getName)
                        .filter(n -> n.toLowerCase().startsWith(typed))
                        .forEach(suggestions::add);
            } else if (isAdmin) {
                if ("--name".startsWith(typed))  suggestions.add("--name");
                if ("--world".startsWith(typed) && !(sender instanceof Player)) suggestions.add("--world");
            }
        }
        return suggestions;
    }
}

package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.World;
import org.bukkit.command.CommandSender;
import org.bukkit.entity.Player;

import java.util.ArrayList;
import java.util.List;

/**
 * {@code /fpp spawn [amount] [--name <name>] [--world <world> [x,y,z]]} — spawns one or more fake players.
 *
 * <h3>Tiers</h3>
 * <ul>
 *   <li><b>Admin</b> ({@code fpp.spawn}) — unlimited count (up to max-bots), optional
 *       {@code --name} flag ({@code fpp.spawn.name}), spawning multiple at once
 *       ({@code fpp.spawn.multiple}). Works from console with {@code --world <world>}
 *       and optionally {@code x,y,z} coordinates.</li>
 *   <li><b>Console</b> — from console, use:
 *       <ul>
 *         <li>{@code /fpp spawn 5} — spawns without body (tab-list only)</li>
 *         <li>{@code /fpp spawn 5 world} — spawns at world spawn location with body</li>
 *         <li>{@code /fpp spawn 5 world 100,64,200} — spawns at specific location with body</li>
 *       </ul>
 *       If no world is specified from console, bot spawns without physical body.</li>
 *   <li><b>User</b> ({@code fpp.user.spawn}) — limited by personal bot limit resolved
 *       from {@code fpp.bot.<n>} permission nodes; falls back to
 *       {@code limits.user-bot-limit} in config. Subject to spawn cooldown unless
 *       {@code fpp.bypass.cooldown} is set.</li>
 * </ul>
 */
@SuppressWarnings("unused") // Registered dynamically via CommandManager.register()
public class SpawnCommand implements FppCommand {

    private final FakePlayerManager manager;

    public SpawnCommand(FakePlayerManager manager) {
        this.manager = manager;
    }

    @Override public String getName()        { return "spawn"; }
    @Override public String getUsage()       { return "[amount] [world [x,y,z]]"; }
    @Override public String getDescription() { return "Spawns one or more fake player bots."; }
    @Override public String getPermission()  { return Perm.SPAWN; }

    /** Both admin-spawn and user-spawn are accepted. */
    @Override
    public boolean canUse(CommandSender sender) {
        return Perm.has(sender, Perm.SPAWN) || Perm.has(sender, Perm.USER_SPAWN);
    }

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        boolean isAdmin = Perm.has(sender, Perm.SPAWN);
        boolean isUser  = !isAdmin && Perm.has(sender, Perm.USER_SPAWN);

        if (!isAdmin && !isUser) {
            sender.sendMessage(Lang.get("no-permission"));
            return true;
        }

        // ── Parse arguments ───────────────────────────────────────────────────
        int    count      = 1;
        String customName = null;
        String worldName  = null;
        double coordX     = 0;
        double coordY     = 0;
        double coordZ     = 0;
        boolean spawnWithoutBody = false;

        boolean isConsole = !(sender instanceof Player);

        // Parse arguments differently for console vs player
        if (isConsole) {
            // Console syntax: /fpp spawn [count] [world [x,y,z]]
            // e.g., /fpp spawn 5
            // e.g., /fpp spawn 5 world
            // e.g., /fpp spawn 5 world 100,64,200
            if (args.length >= 1) {
                try {
                    count = Integer.parseInt(args[0]);
                    if (count <= 0) throw new NumberFormatException();
                } catch (NumberFormatException e) {
                    sender.sendMessage(Lang.get("spawn-invalid"));
                    return true;
                }
            }
            if (args.length >= 2) {
                worldName = args[1];
                World w = Bukkit.getWorld(worldName);
                if (w == null) {
                    sender.sendMessage(Lang.get("spawn-world-not-found", "world", worldName));
                    return true;
                }
            } else {
                // No world specified from console — spawn without body (tab-list only)
                spawnWithoutBody = true;
            }
            if (args.length >= 3) {
                // Parse x,y,z coordinates
                String coordStr = args[2];
                String[] coords = coordStr.split(",");
                if (coords.length != 3) {
                    sender.sendMessage(Lang.get("spawn-invalid-coords"));
                    return true;
                }
                try {
                    coordX = Double.parseDouble(coords[0]);
                    coordY = Double.parseDouble(coords[1]);
                    coordZ = Double.parseDouble(coords[2]);
                } catch (NumberFormatException e) {
                    sender.sendMessage(Lang.get("spawn-invalid-coords"));
                    return true;
                }
            }
        } else {
            // Player syntax: /fpp spawn [amount] [--name <name>] [--world <world>]
            for (int i = 0; i < args.length; i++) {
                switch (args[i].toLowerCase()) {
                    case "--name" -> {
                        if (i + 1 < args.length) {
                            customName = args[++i];
                        } else {
                            sender.sendMessage(Lang.get("spawn-invalid"));
                            return true;
                        }
                    }
                    case "--world" -> {
                        if (i + 1 < args.length) {
                            worldName = args[++i];
                        } else {
                            sender.sendMessage(Lang.get("spawn-invalid"));
                            return true;
                        }
                    }
                    default -> {
                        try {
                            count = Integer.parseInt(args[i]);
                            if (count <= 0) throw new NumberFormatException();
                        } catch (NumberFormatException e) {
                            sender.sendMessage(Lang.get("spawn-invalid"));
                            return true;
                        }
                    }
                }
            }
        }

        // ── Resolve spawn location ─────────────────────────────────────────────
        Location location;
        if (sender instanceof Player player) {
            location = player.getLocation();
            if (worldName != null) {
                World w = Bukkit.getWorld(worldName);
                if (w == null) {
                    sender.sendMessage(Lang.get("spawn-world-not-found", "world", worldName));
                    return true;
                }
                location = w.getSpawnLocation();
            }
        } else {
            // Console spawn
            if (worldName != null) {
                World w = Bukkit.getWorld(worldName);
                if (w == null) {
                    sender.sendMessage(Lang.get("spawn-world-not-found", "world", worldName));
                    return true;
                }
                // Use custom coordinates if provided, otherwise world spawn
                if (args.length >= 3) {
                    location = new Location(w, coordX, coordY, coordZ);
                } else {
                    location = w.getSpawnLocation();
                }
            } else {
                List<World> worlds = Bukkit.getWorlds();
                if (worlds.isEmpty()) {
                    sender.sendMessage(Lang.get("spawn-console-no-world"));
                    return true;
                }
                // Spawn without body — use dummy location (won't be used for body spawning)
                location = worlds.getFirst().getSpawnLocation();
            }
        }

        // ── User-tier spawn ────────────────────────────────────────────────────
        if (isUser) {
            if (!(sender instanceof Player player)) {
                sender.sendMessage(Lang.get("player-only"));
                return true;
            }

            // Cooldown check
            if (!Perm.has(sender, Perm.BYPASS_COOLDOWN) && manager.isOnCooldown(player.getUniqueId())) {
                long remaining = manager.getRemainingCooldown(player.getUniqueId());
                sender.sendMessage(Lang.get("spawn-cooldown", "seconds", String.valueOf(remaining)));
                return true;
            }

            // Enforce personal bot limit
            int permLimit    = Perm.resolveUserBotLimit(sender);
            int limit        = permLimit >= 0 ? permLimit : Config.userBotLimit();
            int alreadyOwned = manager.getBotsOwnedBy(player.getUniqueId()).size();
            if (alreadyOwned >= limit) {
                sender.sendMessage(Lang.get("spawn-user-limit-reached", "limit", String.valueOf(limit)));
                return true;
            }
            count = Math.min(count, limit - alreadyOwned);

            int result = manager.spawnUserBot(location, count, player, false);
            if (result == -1) {
                int max = Config.maxBots();
                sender.sendMessage(Lang.get("spawn-max-reached", "max", String.valueOf(max)));
                return true;
            }
            if (result <= 0) {
                sender.sendMessage(Lang.get("spawn-no-names-left"));
                return true;
            }

            manager.recordSpawnCooldown(player.getUniqueId());
            int total = manager.getCount();
            sender.sendMessage(Lang.get("spawn-success",
                    "count", String.valueOf(result),
                    "total", String.valueOf(total)));
            return true;
        }

        // ── Admin-tier spawn ───────────────────────────────────────────────────

        // Cooldown check (admins also subject to cooldown unless bypassed)
        if (sender instanceof Player player
                && !Perm.has(sender, Perm.BYPASS_COOLDOWN)
                && manager.isOnCooldown(player.getUniqueId())) {
            long remaining = manager.getRemainingCooldown(player.getUniqueId());
            sender.sendMessage(Lang.get("spawn-cooldown", "seconds", String.valueOf(remaining)));
            return true;
        }

        // Multiple bots — check sub-permission
        if (count > 1 && !Perm.has(sender, Perm.SPAWN_MULTIPLE)) {
            sender.sendMessage(Lang.get("no-permission"));
            return true;
        }

        // Custom name — check sub-permission
        if (customName != null && !Perm.has(sender, Perm.SPAWN_CUSTOM_NAME)) {
            sender.sendMessage(Lang.get("no-permission"));
            return true;
        }

        boolean bypassMax = Perm.has(sender, Perm.BYPASS_MAX);
        Player  spawner   = (sender instanceof Player p) ? p : null;

        // Use spawnBodyless if flag is set (console without location data)
        int result;
        if (spawnWithoutBody) {
            result = manager.spawnBodyless(location, count, spawner, customName, bypassMax, true);
        } else {
            result = manager.spawn(location, count, spawner, customName, bypassMax);
        }

        switch (result) {
            case -1 -> {
                int max = Config.maxBots();
                sender.sendMessage(Lang.get("spawn-max-reached", "max", String.valueOf(max)));
            }
            case -2 -> sender.sendMessage(Lang.get("spawn-invalid-name"));
            case 0 -> {
                if (customName != null) {
                    sender.sendMessage(Lang.get("spawn-name-taken", "name", customName));
                } else {
                    sender.sendMessage(Lang.get("spawn-no-names-left"));
                }
            }
            default -> {
                if (sender instanceof Player p) {
                    manager.recordSpawnCooldown(p.getUniqueId());
                }
                int total = manager.getCount();
                sender.sendMessage(Lang.get("spawn-success",
                        "count", String.valueOf(result),
                        "total", String.valueOf(total)));
            }
        }
        return true;
    }

    @Override
    public List<String> tabComplete(CommandSender sender, String[] args) {
        if (!canUse(sender)) return List.of();

        boolean isAdmin = Perm.has(sender, Perm.SPAWN);
        List<String> suggestions = new ArrayList<>();

        if (args.length == 1) {
            String typed = args[0].toLowerCase();
            if (isAdmin) {
                Config.spawnCountPresetsAdmin().stream()
                        .filter(s -> s.startsWith(typed))
                        .forEach(suggestions::add);
            } else {
                int permLimit = Perm.resolveUserBotLimit(sender);
                int limit     = permLimit >= 0 ? permLimit : Config.userBotLimit();
                for (int i = 1; i <= Math.min(limit, 10); i++) {
                    String s = String.valueOf(i);
                    if (s.startsWith(typed)) suggestions.add(s);
                }
            }
            if (isAdmin && "--name".startsWith(typed)) suggestions.add("--name");
            if ("--world".startsWith(typed) && !(sender instanceof Player)) suggestions.add("--world");
        } else if (args.length >= 2) {
            String prev  = args[args.length - 2].toLowerCase();
            String typed = args[args.length - 1].toLowerCase();
            if (prev.equals("--world")) {
                Bukkit.getWorlds().stream()
                        .map(World::getName)
                        .filter(n -> n.toLowerCase().startsWith(typed))
                        .forEach(suggestions::add);
            } else if (isAdmin) {
                if ("--name".startsWith(typed))  suggestions.add("--name");
                if ("--world".startsWith(typed) && !(sender instanceof Player)) suggestions.add("--world");
            }
        }
        return suggestions;
    }
}

package me.bill.fakePlayerPlugin.util;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import org.bukkit.Bukkit;

import java.io.OutputStream;
import java.net.HttpURLConnection;
import java.net.URI;
import java.nio.charset.StandardCharsets;

/**
 * Periodically POSTs server/player/bot counts to the FPP Vercel API so the
 * website homepage shows real-time statistics.
 *
 * <h3>Payload (JSON)</h3>
 * <pre>{@code
 * {
 *   "server_id":    "<database.server-id>",
 *   "player_count": <real online players (excludes bots)>,
 *   "bot_count":    <active fake bots>,
 *   "version":      "<plugin version>"
 * }
 * }</pre>
 *
 * <p>Heartbeats fire every {@value #INTERVAL_TICKS} ticks (~5 minutes) on an
 * async Bukkit thread and never block the main thread.
 * Controlled by {@code heartbeat.enabled} in {@code config.yml}.
 *
 * <p>The endpoint stores the data in Vercel KV (Redis).  When KV is not yet
 * configured on the Vercel project the endpoint returns HTTP 503, which this
 * class silently ignores — no errors are printed to the server console unless
 * {@code logging.debug.network} is enabled.
 */
public final class StatsHeartbeat {

    /** Heartbeat endpoint on the FPP Vercel deployment. */
    private static final String HEARTBEAT_URL =
            "https://fake-player-plugin.vercel.app/api/heartbeat";    /** 5 minutes in ticks (20 ticks/s × 60 s × 5). */
    private static final long INTERVAL_TICKS = 20L * 60L * 5L;

    /**
     * Initial delay before the first heartbeat fires.
     * 20 seconds gives bots time to finish restoring from persistence so the
     * first payload reflects the real active bot count.
     */
    private static final long INITIAL_DELAY_TICKS = 20L * 20L;

    private final FakePlayerPlugin  plugin;
    private final FakePlayerManager manager;

    /** Bukkit task ID of the repeating heartbeat task, or {@code -1} when stopped. */
    private int taskId = -1;

    public StatsHeartbeat(FakePlayerPlugin plugin, FakePlayerManager manager) {
        this.plugin  = plugin;
        this.manager = manager;
    }

    /**
     * Starts the repeating heartbeat task.
     * No-op if already running or if {@code heartbeat.enabled} is {@code false}.
     */
    public void start() {
        if (taskId != -1) return;
        if (!Config.heartbeatEnabled()) {
            Config.debugStartup("StatsHeartbeat disabled in config — skipping.");
            return;
        }
        taskId = Bukkit.getScheduler()
                .runTaskTimerAsynchronously(plugin, this::sendHeartbeat,
                        INITIAL_DELAY_TICKS, INTERVAL_TICKS)
                .getTaskId();
        Config.debugStartup("StatsHeartbeat started (interval=5 min, url=" + HEARTBEAT_URL + ").");
    }

    /** Cancels the repeating heartbeat task. */
    public void stop() {
        if (taskId != -1) {
            Bukkit.getScheduler().cancelTask(taskId);
            taskId = -1;
            Config.debugStartup("StatsHeartbeat stopped.");
        }
    }

    // ── Private ───────────────────────────────────────────────────────────────

    /** Builds and sends a single heartbeat POST. Always runs on an async thread. */
    private void sendHeartbeat() {
        try {
            int botCount    = manager.getCount();
            // Bots appear in getOnlinePlayers() — subtract them to get real players.
            int playerCount = Math.max(0, Bukkit.getOnlinePlayers().size() - botCount);
            String version  = plugin.getPluginMeta().getVersion();
            String serverId = Config.serverId();

            String json = "{"
                    + "\"server_id\":"    + "\"" + escapeJson(serverId) + "\""
                    + ",\"player_count\":" + playerCount
                    + ",\"bot_count\":"    + botCount
                    + ",\"version\":"     + "\"" + escapeJson(version) + "\""
                    + "}";

            byte[] body = json.getBytes(StandardCharsets.UTF_8);

            HttpURLConnection conn =
                    (HttpURLConnection) URI.create(HEARTBEAT_URL).toURL().openConnection();
            conn.setRequestMethod("POST");
            conn.setConnectTimeout(6_000);
            conn.setReadTimeout(6_000);
            conn.setDoOutput(true);
            conn.setRequestProperty("Content-Type", "application/json; charset=UTF-8");
            conn.setRequestProperty("Content-Length", String.valueOf(body.length));
            conn.setRequestProperty("User-Agent",
                    "FakePlayerPlugin-Heartbeat/" + version
                    + " (https://modrinth.com/plugin/fake-player-plugin-(fpp))");
            conn.setRequestProperty("X-Plugin-Request", "true");

            try (OutputStream out = conn.getOutputStream()) {
                out.write(body);
            }

            int code = conn.getResponseCode();
            Config.debugNetwork("StatsHeartbeat: sent"
                    + " server=" + serverId
                    + " bots=" + botCount
                    + " players=" + playerCount
                    + " → HTTP " + code + ".");

        } catch (Exception e) {
            // Network errors are non-critical — only log in debug mode
            Config.debugNetwork("StatsHeartbeat: send failed — " + e.getMessage());
        }
    }

    /**
     * Minimal JSON string escaping — handles backslash, double-quote, and the
     * most common control characters so the payload is always valid JSON.
     */
    private static String escapeJson(String s) {
        if (s == null) return "";
        return s.replace("\\", "\\\\")
                .replace("\"", "\\\"")
                .replace("\n", "\\n")
                .replace("\r", "\\r")
                .replace("\t", "\\t");
    }
}

