package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.BotSwapAI;
import me.bill.fakePlayerPlugin.fakeplayer.BotType;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayer;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;
import org.bukkit.command.CommandSender;

import java.util.List;
import java.util.Set;
import java.util.UUID;
import java.util.stream.Collectors;

/**
 * {@code /fpp swap [on|off|status|now <bot>|list]}
 *
 * <p>Controls the bot session-rotation system. When enabled, AFK bots
 * periodically leave and rejoin the server, mimicking real player behaviour.
 *
 * <ul>
 *   <li>{@code /fpp swap}             — <strong>toggle</strong> swap on/off (no args = flip current state)</li>
 *   <li>{@code /fpp swap on}          — enable swap and start session countdowns</li>
 *   <li>{@code /fpp swap off}         — disable swap and cancel all countdowns</li>
 *   <li>{@code /fpp swap status}      — show status (active sessions + offline count)</li>
 *   <li>{@code /fpp swap now <bot>}   — trigger an immediate leave for a specific bot</li>
 *   <li>{@code /fpp swap list}        — list all bots with their personality and swap count</li>
 * </ul>
 */
public class SwapCommand implements FppCommand {

    private final FakePlayerPlugin  plugin;
    private final FakePlayerManager manager;

    public SwapCommand(FakePlayerPlugin plugin, FakePlayerManager manager) {
        this.plugin  = plugin;
        this.manager = manager;
    }

    @Override public String getName()        { return "swap"; }
    @Override public String getUsage()       { return "[on|off|status|now <bot>|list]"; }
    @Override public String getDescription() { return "Toggle bot session rotation (swap in / out)."; }
    @Override public String getPermission()  { return Perm.SWAP; }

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        // No args → toggle (mirrors /fpp chat behaviour)
        if (args.length == 0) {
            boolean enable = !Config.swapEnabled();
            if (enable) enableSwap(sender);
            else disableSwap(sender);
            Config.debug("swap toggled to " + enable + " by " + sender.getName());
            return true;
        }

        switch (args[0].toLowerCase()) {

            case "on", "true", "yes", "1" -> enableSwap(sender);

            case "off", "false", "no", "0" -> disableSwap(sender);

            case "status" -> sendStatus(sender);

            case "now" -> {
                if (args.length < 2) {
                    sender.sendMessage(Lang.get("swap-now-usage"));
                    return true;
                }
                String botName = args[1];
                BotSwapAI ai = plugin.getBotSwapAI();
                if (ai == null) {
                    sender.sendMessage(Lang.get("swap-not-available"));
                    return true;
                }
                if (ai.triggerNow(botName)) {
                    sender.sendMessage(Lang.get("swap-now-success", "name", botName));
                } else {
                    sender.sendMessage(Lang.get("swap-now-failed", "name", botName));
                }
            }

            case "list" -> sendList(sender);

            default -> sender.sendMessage(Lang.get("swap-invalid"));
        }

        return true;
    }

    // ── Display helpers ───────────────────────────────────────────────────────

    private void sendStatus(CommandSender sender) {
        boolean on   = Config.swapEnabled();
        BotSwapAI ai = plugin.getBotSwapAI();

        if (on && ai != null) {
            long nextSec = ai.getNextSwapSeconds();
            String nextLabel = nextSec >= 0
                    ? (nextSec >= 60 ? (nextSec / 60) + "m " + (nextSec % 60) + "s" : nextSec + "s")
                    : "none";
            sender.sendMessage(Lang.get("swap-status-on",
                    "sessions", String.valueOf(ai.getActiveSessionCount()),
                    "offline",  String.valueOf(ai.getSwappedOutCount()),
                    "next",     nextLabel));
        } else {
            sender.sendMessage(Lang.get("swap-status-off"));
        }
    }

    private void sendList(CommandSender sender) {
        BotSwapAI ai = plugin.getBotSwapAI();
        if (ai == null || ai.getActiveSessions().isEmpty()) {
            sender.sendMessage(Lang.get("swap-list-empty"));
            return;
        }

        Set<UUID> sessions = ai.getActiveSessions();
        List<FakePlayer> scheduled = manager.getActivePlayers().stream()
                .filter(fp -> sessions.contains(fp.getUuid()))
                .collect(Collectors.toList());

        if (scheduled.isEmpty()) {
            sender.sendMessage(Lang.get("swap-list-empty"));
            return;
        }

        sender.sendMessage(Lang.get("swap-list-header",
                "count", String.valueOf(scheduled.size())));

        for (FakePlayer fp : scheduled) {
            sender.sendMessage(Lang.get("swap-list-entry",
                    "name",        fp.getDisplayName(),
                    "personality", ai.getPersonalityLabel(fp.getUuid()),
                    "swaps",       String.valueOf(ai.getSwapCount(fp.getUuid()))));
        }
    }

    // ── Tab-complete ──────────────────────────────────────────────────────────

    @Override
    public List<String> tabComplete(CommandSender sender, String[] args) {
        if (args.length == 1) {
            String pfx = args[0].toLowerCase();
            return List.of("on", "off", "status", "now", "list")
                    .stream()
                    .filter(s -> s.startsWith(pfx))
                    .collect(Collectors.toList());
        }
        if (args.length == 2 && args[0].equalsIgnoreCase("now")) {
            String pfx = args[1].toLowerCase();
            return manager.getActiveNames().stream()
                    .filter(n -> n.toLowerCase().startsWith(pfx))
                    .collect(Collectors.toList());
        }
        return List.of();
    }
}

package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.BotSwapAI;
import me.bill.fakePlayerPlugin.fakeplayer.BotType;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayer;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;
import org.bukkit.command.CommandSender;

import java.util.List;
import java.util.Set;
import java.util.UUID;
import java.util.stream.Collectors;

/**
 * {@code /fpp swap [on|off|status|now <bot>|list]}
 *
 * <p>Controls the bot session-rotation system. When enabled, AFK bots
 * periodically leave and rejoin the server, mimicking real player behaviour.
 *
 * <ul>
 *   <li>{@code /fpp swap}             — <strong>toggle</strong> swap on/off (no args = flip current state)</li>
 *   <li>{@code /fpp swap on}          — enable swap and start session countdowns</li>
 *   <li>{@code /fpp swap off}         — disable swap and cancel all countdowns</li>
 *   <li>{@code /fpp swap status}      — show status (active sessions + offline count)</li>
 *   <li>{@code /fpp swap now <bot>}   — trigger an immediate leave for a specific bot</li>
 *   <li>{@code /fpp swap list}        — list all bots with their personality and swap count</li>
 * </ul>
 */
public class SwapCommand implements FppCommand {

    private final FakePlayerPlugin  plugin;
    private final FakePlayerManager manager;

    public SwapCommand(FakePlayerPlugin plugin, FakePlayerManager manager) {
        this.plugin  = plugin;
        this.manager = manager;
    }

    @Override public String getName()        { return "swap"; }
    @Override public String getUsage()       { return "[on|off|status|now <bot>|list]"; }
    @Override public String getDescription() { return "Toggle bot session rotation (swap in / out)."; }
    @Override public String getPermission()  { return Perm.SWAP; }

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        // No args → toggle (mirrors /fpp chat behaviour)
        if (args.length == 0) {
            boolean enable = !Config.swapEnabled();
            if (enable) enableSwap(sender);
            else disableSwap(sender);
            Config.debug("swap toggled to " + enable + " by " + sender.getName());
            return true;
        }

        switch (args[0].toLowerCase()) {

            case "on", "true", "yes", "1" -> enableSwap(sender);

            case "off", "false", "no", "0" -> disableSwap(sender);

            case "status" -> sendStatus(sender);

            case "now" -> {
                if (args.length < 2) {
                    sender.sendMessage(Lang.get("swap-now-usage"));
                    return true;
                }
                String botName = args[1];
                BotSwapAI ai = plugin.getBotSwapAI();
                if (ai == null) {
                    sender.sendMessage(Lang.get("swap-not-available"));
                    return true;
                }
                if (ai.triggerNow(botName)) {
                    sender.sendMessage(Lang.get("swap-now-success", "name", botName));
                } else {
                    sender.sendMessage(Lang.get("swap-now-failed", "name", botName));
                }
            }

            case "list" -> sendList(sender);

            default -> sender.sendMessage(Lang.get("swap-invalid"));
        }

        return true;
    }

    // ── Enable / disable helpers ─────────────────────────────────────────────

    private void enableSwap(CommandSender sender) {
        plugin.getConfig().set("swap.enabled", true);
        plugin.saveConfig();

        BotSwapAI ai = plugin.getBotSwapAI();
        int scheduled = 0;
        if (ai != null) {
            for (FakePlayer fp : manager.getActivePlayers()) {
                if (fp.getBotType() != BotType.PVP) {
                    ai.schedule(fp);
                    scheduled++;
                }
            }
        }
        if (scheduled > 0 && ai != null) {
            long nextSec = ai.getNextSwapSeconds();
            String nextLabel = nextSec >= 0
                    ? (nextSec >= 60 ? (nextSec / 60) + "m " + (nextSec % 60) + "s" : nextSec + "s")
                    : "soon";
            sender.sendMessage(Lang.get("swap-enabled",
                    "count", String.valueOf(scheduled),
                    "next",  nextLabel));
        } else {
            sender.sendMessage(Lang.get("swap-enabled",
                    "count", "0",
                    "next",  "—"));
        }
        Config.debug("swap.enabled set to true by enableSwap()");
    }

    private void disableSwap(CommandSender sender) {
        plugin.getConfig().set("swap.enabled", false);
        plugin.saveConfig();

        BotSwapAI ai = plugin.getBotSwapAI();
        int cancelled = ai != null ? ai.getActiveSessionCount() : 0;
        int offline   = ai != null ? ai.getSwappedOutCount()    : 0;
        if (ai != null) ai.cancelAll();
        sender.sendMessage(Lang.get("swap-disabled",
                "count",   String.valueOf(cancelled),
                "offline", String.valueOf(offline)));
        Config.debug("swap.enabled set to false by disableSwap()");
    }

    // ── Display helpers ───────────────────────────────────────────────────────

    private void sendStatus(CommandSender sender) {
        boolean on   = Config.swapEnabled();
        BotSwapAI ai = plugin.getBotSwapAI();

        if (on && ai != null) {
            long nextSec = ai.getNextSwapSeconds();
            String nextLabel = nextSec >= 0
                    ? (nextSec >= 60 ? (nextSec / 60) + "m " + (nextSec % 60) + "s" : nextSec + "s")
                    : "none";
            sender.sendMessage(Lang.get("swap-status-on",
                    "sessions", String.valueOf(ai.getActiveSessionCount()),
                    "offline",  String.valueOf(ai.getSwappedOutCount()),
                    "next",     nextLabel));
        } else {
            sender.sendMessage(Lang.get("swap-status-off"));
        }
    }

    private void sendList(CommandSender sender) {
        BotSwapAI ai = plugin.getBotSwapAI();
        if (ai == null || ai.getActiveSessions().isEmpty()) {
            sender.sendMessage(Lang.get("swap-list-empty"));
            return;
        }

        Set<UUID> sessions = ai.getActiveSessions();
        List<FakePlayer> scheduled = manager.getActivePlayers().stream()
                .filter(fp -> sessions.contains(fp.getUuid()))
                .collect(Collectors.toList());

        if (scheduled.isEmpty()) {
            sender.sendMessage(Lang.get("swap-list-empty"));
            return;
        }

        sender.sendMessage(Lang.get("swap-list-header",
                "count", String.valueOf(scheduled.size())));

        for (FakePlayer fp : scheduled) {
            sender.sendMessage(Lang.get("swap-list-entry",
                    "name",        fp.getDisplayName(),
                    "personality", ai.getPersonalityLabel(fp.getUuid()),
                    "swaps",       String.valueOf(ai.getSwapCount(fp.getUuid()))));
        }
    }

    // ── Tab-complete ──────────────────────────────────────────────────────────

    @Override
    public List<String> tabComplete(CommandSender sender, String[] args) {
        if (args.length == 1) {
            String pfx = args[0].toLowerCase();
            return List.of("on", "off", "status", "now", "list")
                    .stream()
                    .filter(s -> s.startsWith(pfx))
                    .collect(Collectors.toList());
        }
        if (args.length == 2 && args[0].equalsIgnoreCase("now")) {
            String pfx = args[1].toLowerCase();
            return manager.getActiveNames().stream()
                    .filter(n -> n.toLowerCase().startsWith(pfx))
                    .collect(Collectors.toList());
        }
        return List.of();
    }
}

const express = require("express");
const cors = require("cors");
const fs = require("fs");
const path = require("path");
const yaml = require("js-yaml");
const fetch = require("node-fetch");

const app = express();
const port = process.env.PORT || 3000;

app.use(cors());

// Middleware to check if request is from plugin (for API protection)
function isPluginRequest(req) {
  const userAgent = req.get('User-Agent') || '';
  const pluginHeaders = req.get('X-Plugin-Request') || req.get('X-FPP-Request');

  // Allow requests from Java HTTP clients (plugin) or with plugin headers
  return userAgent.includes('Java') ||
         userAgent.includes('Apache-HttpClient') ||
         pluginHeaders === 'true' ||
         req.ip === '127.0.0.1' ||
         req.ip === '::1';
}

// API protection middleware
function protectAPI(req, res, next) {
  if (isPluginRequest(req)) {
    next();
  } else {
    res.status(403).json({ error: 'API access restricted to plugin requests.' });
  }
}

// ── API ROUTES (must come BEFORE static middleware) ─────────────────────────

// ── Online stats endpoint (public - no auth required) ───────────────────────
// Returns the count of servers and users currently using the plugin
app.get('/api/online-stats', async (req, res) => {
  res.json({
    servers: 200,
    users: 630,
    timestamp: new Date().toISOString()
  });
});

// ── Helper functions ─────────────────────────────────────────────────────────

function findProjectRoot(startDir) {
  if (process.env.PLUGIN_ROOT) return path.resolve(process.env.PLUGIN_ROOT);
  let cur = path.resolve(startDir);
  for (let i = 0; i < 8; i++) {
    const candidateA = path.join(cur, "src", "main", "resources", "plugin.yml");
    const candidateB = path.join(cur, "pom.xml");
    const candidateC = path.join(cur, "target");
    if (
      fs.existsSync(candidateA) ||
      fs.existsSync(candidateB) ||
      fs.existsSync(candidateC)
    )
      return cur;
    const parent = path.dirname(cur);
    if (parent === cur) break;
    cur = parent;
  }
  return path.resolve(__dirname);
}

function safeReadYaml(filePath) {
  try {
    if (!fs.existsSync(filePath)) return null;
    const content = fs.readFileSync(filePath, "utf8");
    return yaml.load(content);
  } catch (e) {
    return { error: String(e) };
  }
}

// Helpers to normalize responses to a minimal public shape
function toSafeString(v) {
  if (v === undefined || v === null) return null;
  if (typeof v === "string") return v;
  if (typeof v === "number" || typeof v === "boolean") return String(v);
  return null; // avoid arrays/objects
}

function mapToMinimal(obj) {
  const fallback = {
    name: null,
    version: null,
    downloadUrl: process.env.PLUGIN_DOWNLOAD_URL || "https://api.fpp.com/",
    notes: null,
  };
  if (!obj || typeof obj !== "object") return fallback;
  const name = toSafeString(obj.name || obj.displayName || obj.title) || null;
  const version =
    toSafeString(
      obj.version || obj.tag_name || obj.latest || obj.version_number
    ) || null;
  const downloadUrl =
    toSafeString(obj.downloadUrl || obj.download_url || obj.website) ||
    process.env.PLUGIN_DOWNLOAD_URL ||
    "https://api.fpp.com/";
  const notes =
    toSafeString(obj.description || obj.notes || obj.body || obj.summary) ||
    null;
  return { name, version, downloadUrl, notes };
}

function findBestObject(result) {
  if (!result || typeof result !== "object") return null;
  if (result.version || result.tag_name || result.name || result.latest)
    return result;
  const keys = [
    "plugin",
    "data",
    "release",
    "manifest",
    "result",
    "package",
    "body",
  ];
  for (const k of keys) {
    if (result[k] && typeof result[k] === "object") {
      const candidate = result[k];
      if (
        candidate.version ||
        candidate.tag_name ||
        candidate.name ||
        candidate.latest
      )
        return candidate;
    }
  }
  for (const k of Object.keys(result)) {
    const v = result[k];
    if (v && typeof v === "object") {
      if (v.version || v.tag_name || v.name || v.latest) return v;
    }
  }
  return null;
}

const projectRoot = findProjectRoot(__dirname);
console.log("Using project root:", projectRoot);

// ── Static assets ────────────────────────────────────────────────────────────
// Serve all static files (CSS, JS, images, fonts, .md) from the frontend dir.
// index:false prevents directory index serving; HTML files are handled by explicit routes below.
app.use(express.static(__dirname, {
  dotfiles: 'deny',
  index: false,
}));

// Serve wiki markdown source files at /wiki/*.md
app.use('/wiki', express.static(path.join(__dirname, 'wiki'), { dotfiles: 'deny' }));

// Serve legal markdown source files at /legal/*.md
app.use('/legal', express.static(path.join(__dirname, 'legal'), { dotfiles: 'deny' }));

// ── Protected API routes ─────────────────────────────────────────────────────

app.get("/api/status", protectAPI, async (req, res) => {
  const pluginYmlPath = path.join(
    projectRoot,
    "src",
    "main",
    "resources",
    "plugin.yml"
  );
  const configYmlPath = path.join(
    projectRoot,
    "src",
    "main",
    "resources",
    "config.yml"
  );
  const botNamesPath = path.join(
    projectRoot,
    "src",
    "main",
    "resources",
    "bot-names.yml"
  );
  const botMessagesPath = path.join(
    projectRoot,
    "src",
    "main",
    "resources",
    "bot-messages.yml"
  );
  const languageEnPath = path.join(
    projectRoot,
    "src",
    "main",
    "resources",
    "language",
    "en.yml"
  );
  const skinsDir = path.join(projectRoot, "src", "main", "resources", "skins");
  const pomPropsPath = path.join(
    projectRoot,
    "target",
    "maven-archiver",
    "pom.properties"
  );
  const targetJarDir = path.join(projectRoot, "target");

  const plugin = safeReadYaml(pluginYmlPath);
  // Prefer plugin info from local YAML if present, but normalize to minimal fields
  if (plugin) {
    const bestLocal =
      findBestObject(plugin) ||
      (plugin.plugin && typeof plugin.plugin === "object"
        ? plugin.plugin
        : plugin);
    return res.json(mapToMinimal(bestLocal));
  }

  // fallback: try to proxy to PLUGIN_API_URL if configured
  const pluginApi =
    process.env.PLUGIN_API_URL || process.env.NEXT_PUBLIC_PLUGIN_API_URL;
  if (pluginApi) {
    const candidates = [
      pluginApi,
      pluginApi.endsWith("/")
        ? pluginApi + "api/status"
        : pluginApi + "/api/status",
      pluginApi.endsWith("/")
        ? pluginApi + "api/check-update"
        : pluginApi + "/api/check-update",
      pluginApi.endsWith("/") ? pluginApi + "status" : pluginApi + "/status",
      pluginApi.endsWith("/") ? pluginApi + "latest" : pluginApi + "/latest",
    ];
    for (const c of candidates) {
      try {
        const controller = new AbortController();
        const id = setTimeout(() => controller.abort(), 5000);
        const r = await fetch(c, { signal: controller.signal });
        clearTimeout(id);
        if (!r.ok) continue;
        const json = await r.json();
        const best =
          findBestObject(json) ||
          (typeof json === "object" ? json : { version: String(json).trim() });
        return res.json(mapToMinimal(best));
      } catch (e) {
        // try next
      }
    }
  }

  let pom = null;
  try {
    if (fs.existsSync(pomPropsPath)) {
      const raw = fs.readFileSync(pomPropsPath, "utf8");
      pom = raw.split("\n").reduce((acc, line) => {
        const idx = line.indexOf("=");
        if (idx > 0)
          acc[line.substring(0, idx).trim()] = line.substring(idx + 1).trim();
        return acc;
      }, {});
    }
  } catch (e) {
    pom = { error: String(e) };
  }

  let jar = null;
  try {
    if (fs.existsSync(targetJarDir)) {
      const files = fs.readdirSync(targetJarDir);
      const fppFiles = files.filter(
        (f) => f.startsWith("fpp-") && f.endsWith(".jar")
      );
      if (fppFiles.length) jar = fppFiles.sort().reverse()[0];
    }
  } catch (e) {
    jar = { error: String(e) };
  }

  const skins = (() => {
    try {
      if (fs.existsSync(skinsDir)) return fs.readdirSync(skinsDir);
      return null;
    } catch (e) {
      return { error: String(e) };
    }
  })();

  // If nothing else returned, respond with minimal empty shape
  return res.json({
    name: null,
    version: null,
    downloadUrl: null,
    notes: null,
    error: "No plugin info found locally and no PLUGIN_API_URL responded",
  });
});

// ── Update checker — mirrors Java UpdateChecker.java ─────────────────────────
// Primary: Modrinth API (same URL as the plugin uses)
// Fallback: LATEST_VERSION / PLUGIN_VERSION env var
const MODRINTH_API  = "https://api.modrinth.com/v2/project/fake-player-plugin-(fpp)/version?limit=1";
const MODRINTH_PAGE = "https://modrinth.com/plugin/fake-player-plugin-(fpp)";
const CACHE_TTL_MS  = 5 * 60 * 1000;

let cachedUpdate = null;
let cachedAt     = 0;

/**
 * Semantic version comparison — mirrors compareVersions() in UpdateChecker.java.
 * Returns >0 when a > b, <0 when a < b, 0 when equal.
 */
function compareVersions(a, b) {
  const stripV = v => (v && v.startsWith("v") ? v.slice(1) : v || "");
  const parts  = v => stripV(v).split(".").map(p => parseInt(p, 10) || 0);
  const pa = parts(a), pb = parts(b);
  const len = Math.max(pa.length, pb.length);
  for (let i = 0; i < len; i++) {
    const diff = (pa[i] || 0) - (pb[i] || 0);
    if (diff !== 0) return diff;
  }
  return 0;
}

async function fetchRemoteUpdate() {
  const now = Date.now();
  if (cachedUpdate && cachedUpdate.latestVersion && (now - cachedAt) < CACHE_TTL_MS)
    return cachedUpdate;

  const localVer = readLocalVersion(projectRoot) || "0.0.0";
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), 6000);
  try {
    const r = await fetch(MODRINTH_API, {
      signal: controller.signal,
      headers: {
        "Accept":     "application/json",
        "User-Agent": `FakePlayerPlugin-UpdateChecker/${localVer} (${MODRINTH_PAGE})`,
      },
    });
    clearTimeout(timer);
    if (!r.ok) return { error: `HTTP ${r.status} from Modrinth` };
    const arr = await r.json();
    if (!Array.isArray(arr) || arr.length === 0) return { error: "empty version array from Modrinth" };
    const first = arr[0];
    const latestVersion = first.version_number || null;
    if (!latestVersion) return { error: "no version_number in Modrinth response" };
    const downloadUrl = (first.files && first.files[0] && first.files[0].url) || MODRINTH_PAGE;
    const result = { latestVersion, version: latestVersion, downloadUrl, source: "modrinth" };
    cachedUpdate = result;
    cachedAt = Date.now();
    return result;
  } catch (e) {
    clearTimeout(timer);
    // Env-var fallback when Modrinth is unreachable
    const pinned = process.env.LATEST_VERSION || process.env.PLUGIN_VERSION;
    if (pinned) return { latestVersion: pinned, version: pinned, downloadUrl: MODRINTH_PAGE, source: "env" };
    return { error: String(e) };
  }
}

function readLocalVersion(root) {
  try {
    const p = path.join(root, "src", "main", "resources", "plugin.yml");
    if (fs.existsSync(p)) {
      const obj = yaml.load(fs.readFileSync(p, "utf8"));
      if (obj && obj.version) return String(obj.version);
    }
  } catch (e) {}
  try {
    const p2 = path.join(root, "target", "maven-archiver", "pom.properties");
    if (fs.existsSync(p2)) {
      const raw = fs.readFileSync(p2, "utf8");
      const props = raw.split("\n").reduce((acc, l) => {
        const i = l.indexOf("=");
        if (i > 0) acc[l.substring(0, i).trim()] = l.substring(i + 1).trim();
        return acc;
      }, {});
      if (props.version) return String(props.version);
    }
  } catch (e) {}
  return null;
}

app.get("/api/check-update", protectAPI, async (req, res) => {
  const remote = await fetchRemoteUpdate();
  if (remote && remote.error)
    return res.status(502).json({ error: remote.error, checkedAt: new Date().toISOString() });

  const localVersion  = readLocalVersion(projectRoot);
  const latestVersion = remote ? (remote.latestVersion || remote.version || null) : null;
  const downloadUrl   = remote ? (remote.downloadUrl || MODRINTH_PAGE) : MODRINTH_PAGE;

  const updateAvailable = (localVersion && latestVersion)
    ? compareVersions(latestVersion, localVersion) > 0
    : null;

  res.json({
    localVersion,
    latestVersion,
    remoteVersion:  latestVersion,  // Java extractVersion() compat
    version:        latestVersion,  // Java extractVersion() compat
    version_number: latestVersion,  // Modrinth-style compat
    updateAvailable,
    downloadUrl,
    source:    remote ? remote.source : null,
    checkedAt: new Date().toISOString(),
  });
});


// ── Page routes ─────────────────────────────────────────────────────────────

// Home page
app.get('/', (req, res) => {
  res.sendFile(path.join(__dirname, 'index.html'));
});

// Wiki SPA shell — /wiki and /wiki/<pagename> (but not .md files)
app.get('/wiki', (req, res) => {
  res.sendFile(path.join(__dirname, 'wiki.html'));
});

app.get('/wiki/:page', (req, res) => {
  // If it's a .md file request, let static middleware handle it
  if (req.params.page.endsWith('.md')) {
    return res.sendFile(path.join(__dirname, 'wiki', req.params.page));
  }
  // Otherwise serve the wiki SPA shell
  res.sendFile(path.join(__dirname, 'wiki.html'));
});

// Legal pages — /legal redirects to privacy policy by default
app.get('/legal', (req, res) => {
  res.redirect(301, '/legal/privacy-policy');
});

// Legal SPA shell — /legal/<page>  (.md files already handled by static middleware above)
app.get('/legal/:page', (req, res) => {
  // If it's a .md file request, let static middleware handle it
  if (req.params.page.endsWith('.md')) {
    return res.sendFile(path.join(__dirname, 'legal', req.params.page));
  }
  // Otherwise serve the legal SPA shell
  res.sendFile(path.join(__dirname, 'legal.html'));
});

// ── Catch-all: unknown routes → home page ───────────────────────────────────
app.get('*', (req, res) => {
  if (req.path.startsWith('/api/')) {
    res.status(404).json({ error: 'API endpoint not found.' });
  } else {
    res.sendFile(path.join(__dirname, 'index.html'));
  }
});

app.listen(port, () =>
  console.log("FPP frontend server listening at http://localhost:" + port)
);

const express = require("express");
const cors = require("cors");
const fs = require("fs");
const path = require("path");
const yaml = require("js-yaml");
const fetch = require("node-fetch");

const app = express();
const port = process.env.PORT || 3000;

app.use(cors());

// Middleware to check if request is from plugin (for API protection)
function isPluginRequest(req) {
  const userAgent = req.get('User-Agent') || '';
  const pluginHeaders = req.get('X-Plugin-Request') || req.get('X-FPP-Request');

  // Allow requests from Java HTTP clients (plugin) or with plugin headers
  return userAgent.includes('Java') ||
         userAgent.includes('Apache-HttpClient') ||
         pluginHeaders === 'true' ||
         req.ip === '127.0.0.1' ||
         req.ip === '::1';
}

// API protection middleware
function protectAPI(req, res, next) {
  if (isPluginRequest(req)) {
    next();
  } else {
    res.status(403).json({ error: 'API access restricted to plugin requests.' });
  }
}

